_guest_profiles = {}    # key -> {key, names:[], phone, email, reservations:[{id,unit,checkin,checkout,nights,total,ts}],
                        #         summaries:[{ts,conversation_id,text}], notes, vip, first_seen, last_seen, total_nights, total_revenue}
