_deep_clean_state = {}
# Listings the owner has manually parked (out of rotation). When paused, the unit
# is skipped by every scheduling function and shown in a separate dashboard
# section. Persisted across redeploys.
_paused_units = set()

# ===================== MAINTENANCE TICKETS (صيانة) =====================
# A lightweight task tracker. Every escalation that gets posted to the
# operations channel ALSO opens a ticket here so the team has a permanent
# audit trail with who-did-what, status, priority, vendor, cost. Tickets
# also serve as the home for problems detected by AI review-analysis.
#
# Schema (per ticket):
#   id           "tk_<ts><rand>"
#   title        short Arabic title
#   description  free-form body
#   status       "open" | "in_progress" | "fixed" | "cancelled"
#   priority     "low" | "med" | "high" | "urgent"
#   category     "صيانة" | "كهرباء" | "سباكة" | "تنظيف" | "تكييف" | "أثاث" |
#                "أجهزة" | "إنترنت" | "أقفال" | "أخرى"
#   lid          related Hostaway listing id (int) or None
#   unit_name    snapshot of the apartment name (so it survives renames)
#   assignee     team-member name string or None
#   due_date     ISO date string or None
#   cost         number SAR or None
#   vendor       free-form vendor name or None
#   vendor_phone string or None
#   source       "manual" | "escalation" | "review"
#   source_ref   the originating escalation/review id (string) or None
#   guest        guest name snapshot when source=escalation
#   created_at   ISO timestamp
#   created_by   "bot" or team-member name
#   log          list of {ts, who, what} events for the audit trail
_tickets = []  # newest-first
_ticket_seq = 0

_TICKET_CATS = ["صيانة", "كهرباء", "سباكة", "تنظيف", "تكييف", "أثاث",
                "أجهزة", "إنترنت", "أقفال", "أخرى"]
_TICKET_STATUSES  = ["open", "in_progress", "fixed", "cancelled"]
_TICKET_PRIORITY  = ["low", "med", "high", "urgent"]

def _new_ticket_id():
    # Monotonic counter + millisecond timestamp → collision-free even in tight loops
    global _ticket_seq
    _ticket_seq += 1
    return f"tk_{int(time.time() * 1000)}_{_ticket_seq:06d}"

def _ticket_log(t, who, what):
    """Append an audit-trail entry. Caps at 50."""
    t.setdefault("log", []).append({
        "ts": datetime.now(TZ).isoformat(timespec="seconds"),
        "who": (who or "bot")[:40],
        "what": (what or "")[:300],
    })
    if len(t["log"]) > 50:
        t["log"] = t["log"][-50:]

def _ticket_create(title, *, description="", lid=None, priority="med",
                   category="صيانة", source="manual", source_ref=None,
                   guest=None, created_by="bot", assignee=None,
                   due_date=None, vendor=None, vendor_phone=None, cost=None):
    """Create + register a ticket. Returns the dict."""
    lid_int = None
    try:
        if lid is not None:
            lid_int = int(lid)
    except Exception:
        lid_int = None
    unit_name = None
    if lid_int is not None:
        unit_name = next((u.get("name") for u in _catalog_units
                          if u.get("id") == lid_int), None) \
                    or (get_listings_map() or {}).get(lid_int) \
                    or str(lid_int)
    t = {
        "id": _new_ticket_id(),
        "title": (title or "بدون عنوان")[:120],
        "description": (description or "")[:2000],
        "status": "open",
        "priority": priority if priority in _TICKET_PRIORITY else "med",
        "category": category if category in _TICKET_CATS else "صيانة",
        "lid": lid_int,
        "unit_name": unit_name,
        "assignee": assignee,
        "due_date": due_date,
        "cost": cost,
        "vendor": vendor,
        "vendor_phone": vendor_phone,
        "source": source if source in ("manual", "escalation", "review") else "manual",
        "source_ref": source_ref,
        "guest": guest,
        "created_at": datetime.now(TZ).isoformat(timespec="seconds"),
        "created_by": created_by or "bot",
        "log": [],
    }
    _ticket_log(t, created_by or "bot",
                f"فتح التذكرة (المصدر: {t['source']})")
    _tickets.insert(0, t)
    # Cap memory at 2000 tickets — older ones drop off
    if len(_tickets) > 2000:
        del _tickets[2000:]
    log_event("ops", f"تذكرة جديدة [{t['category']}]: {t['title']}"
                     + (f" · {unit_name}" if unit_name else ""))
    return t

def _ticket_from_escalation(esc_id, esc):
    """Create (or return existing) ticket linked to an escalation. Idempotent
    by source_ref so duplicate fires from retries don't open duplicate tickets."""
    ref = str(esc_id)
    for t in _tickets:
        if t.get("source") == "escalation" and str(t.get("source_ref")) == ref:
            return t
    unit = esc.get("unit") or "—"
    guest = esc.get("guest") or "—"
    reason = (esc.get("reason") or "").strip()
    last_msg = (esc.get("guest_text") or "").strip().replace("\n", " ")
    title = f"تصعيد · {unit} · {guest}"[:120]
    body_lines = []
    if reason:
        body_lines.append(f"السبب: {reason}")
    if last_msg:
        body_lines.append("آخر رسالة من الضيف:")
        body_lines.append(last_msg[:500])
    if esc.get("conversation_id"):
        body_lines.append(f"\nمحادثة Hostaway: {esc['conversation_id']}")
    description = "\n".join(body_lines)
    lid = None
    # try to resolve the listing-id from the unit name
    try:
        listings = get_listings_map() or {}
        for k, v in listings.items():
            if v and unit and v.strip() == unit.strip():
                lid = int(k); break
    except Exception:
        pass
    return _ticket_create(
        title=title,
        description=description,
        lid=lid,
        priority="high",
        category="صيانة",
        source="escalation",
        source_ref=ref,
        guest=guest,
        created_by="bot",
    )

def fetch_reviews_from_hostaway(limit=20000, page_size=100):
    """Pull recent reviews from Hostaway across all listings. Returns list of
    normalised review dicts (newest first). Default cap is 20k — effectively
    "all of them" for any account we'd reasonably serve. The owner's account
    has ~14.6k reviews on disk so this comfortably covers every published one."""
    out = []
    offset = 0
    while len(out) < limit:
        batch_size = min(page_size, limit - len(out))
        try:
            j = api_get("/v1/reviews", params={"limit": batch_size, "offset": offset,
                                               "sortOrder": "departureDate:desc"})
        except Exception as e:
            print("fetch_reviews_from_hostaway error:", e)
            break
        rows = (j or {}).get("result") or []
        if not rows:
            break
        for r in rows:
            rid = str(r.get("id") or "")
            if not rid:
                continue
            rating_10 = r.get("rating") or r.get("overallRating") or 0
            try:
                rating_5 = int(round(float(rating_10) / 2)) if rating_10 else 0
            except Exception:
                rating_5 = 0
            # Try multiple date fields — Hostaway varies between endpoints
            date_str = (r.get("submittedAt") or r.get("departureDate")
                        or r.get("insertedOn") or r.get("date") or "")
            out.append({
                "id": rid,
                "listing_id": r.get("listingMapId") or r.get("listingId"),
                "rating": rating_5,
                "rating_raw": rating_10,
                "guest_name": (r.get("guestName") or r.get("guest_name")
                               or r.get("reviewerName") or "").strip(),
                "public_review": (r.get("publicReview") or r.get("public_review") or "").strip(),
                "private_review": (r.get("privateReview") or "").strip(),
                "channel": (r.get("channelName") or r.get("channel") or "").strip() or "Airbnb",
                "date": str(date_str)[:10] if date_str else "",
                "is_public": bool(r.get("isPublic", True)),
                "reservation_id": r.get("reservationId"),
                "raw": r,
            })
        if len(rows) < batch_size:
            break
        offset += batch_size
    return out

def refresh_reviews():
    """Fetch + merge into _reviews. Returns number fetched from Hostaway."""
    global _reviews_last_fetch
    fresh = fetch_reviews_from_hostaway()
    # When Hostaway returns the live version of a review we already hold from the
    # CSV seed (same reservation), drop the seed copy first so it isn't shown twice.
    seed_by_resid = {}
    for k, v in list(_reviews.items()):
        if str(v.get("source")) == "csv" and v.get("reservation_id"):
            seed_by_resid.setdefault(str(v["reservation_id"]), []).append(k)
    for r in fresh:
        resid = str(r.get("reservation_id") or "")
        if resid and resid in seed_by_resid:
            for sk in seed_by_resid.pop(resid):
                _reviews.pop(sk, None)
        _reviews[r["id"]] = r
    _reviews_last_fetch = int(time.time())
    return len(fresh)

def merge_reviews_seed():
    """Load the shipped reviews_seed.json (full Airbnb history exported from
    Hostaway) into _reviews for any reservation not already present — live and
    persisted reviews always win. This makes the Reviews page show the whole
    history immediately, even on a fresh deploy before the first live pull."""
    try:
        path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "reviews_seed.json")
        with open(path, encoding="utf-8") as f:
            data = json.load(f) or {}
    except FileNotFoundError:
        return 0
    except Exception as e:
        print("merge_reviews_seed error:", e)
        return 0
    seed = data.get("reviews") or {}
    have = set()
    for v in _reviews.values():
        if v.get("reservation_id"):
            have.add(str(v["reservation_id"]))
    added = 0
    for k, v in seed.items():
        if not isinstance(v, dict):
            continue
        resid = str(v.get("reservation_id") or "")
        if resid and resid in have:
            continue
        if k not in _reviews:
            _reviews[k] = v
            added += 1
            if resid:
                have.add(resid)
    return added

# AI prompt for review analysis — applies AAA framework (Acknowledge, Apologize,
# Act) + Ritz-Carlton "ladies and gentlemen" tone for public responses, and the
# Airbnb review-removal policy rubric for the dispute analysis.
# Includes a "positive review" branch: short, warm, witty (ذرب) Najdi thank-yous.
_REVIEW_AI_SYSTEM = (
    "You are the warm, sharp-witted (ذرب) public-face of Ouja Residence — a "
    "Saudi luxury short-term-rental brand in Riyadh. You handle every review "
    "(positive and negative) from Airbnb / Booking. For each review you "
    "receive, output a SINGLE JSON object with EXACTLY these keys (no extra "
    "prose, no markdown fences):\n"
    "{\n"
    '  "removability": "high" | "medium" | "low" | "none",\n'
    '  "removability_reason_ar": "one-paragraph Arabic explanation (or empty if positive)",\n'
    '  "policy_reference": "the EXACT Airbnb Reviews Policy ground that applies + the help article, e.g. \\"Airbnb Reviews Policy — Biased reviews / content outside the host\'s control (airbnb.com/help/article/2673)\\". Empty if not removable or positive.",\n'
    '  "dispute_angle_ar": "Arabic note for the team — empty if positive",\n'
    '  "dispute_message_en": "polished English message to Airbnb support — empty if positive",\n'
    '  "public_response_ar": "Arabic public reply",\n'
    '  "public_response_en": "English public reply",\n'
    '  "is_positive": true | false\n'
    "}\n\n"
    "FIRST decide: is this review positive (4-5 stars / ≥ 8 of 10) or negative?\n\n"
    "================ POSITIVE PATH (4-5 stars) ================\n"
    "• removability = \"none\". Leave removability_reason_ar, dispute_angle_ar, "
    "dispute_message_en as empty strings.\n"
    "• is_positive = true.\n"
    "• Write a SHORT (1-3 sentences), warm, witty, personal Najdi/Saudi thank-you. "
    "Make it ذرب: sharp, friendly, has personality — NOT robotic, NOT corporate. "
    "Address the guest by FIRST NAME if available. Reference something specific "
    "from their review when possible (e.g. they mentioned the TV → mention the TV). "
    "Use natural Saudi expressions like: \"يا غالينا\"، \"نورتونا\"، \"تكفون "
    "رجعوا\"، \"ما يطيب الكلام منكم\"، \"الشرف لنا\". Avoid bland phrases like "
    "'thank you for your feedback'. Close Arabic with: 'فريق عوجا للسكن 🌿' "
    "(NO formal sign-off). Close English with: 'Warm regards, OUJA Residence 🌿'.\n\n"
    "================ NEGATIVE PATH (1-3 stars or complaint) ================\n"
    "• Set removability per the rubric below.\n"
    "• is_positive = false.\n"
    "• Fill ALL fields including dispute message + public response.\n\n"
    "AIRBNB REVIEWS POLICY — the canonical reference (cite this, do NOT invent "
    "URLs). Airbnb's Review Policy lives at airbnb.com/help/article/2673. A review "
    "may be removed when it:\n"
    "  (a) is BIASED — written to extort/retaliate (guest threatened a bad review "
    "for a refund/discount), or is a retaliatory/incentivised review;\n"
    "  (b) contains IRRELEVANT content — not about the actual stay or the guest's "
    "genuine experience (politics, the neighbourhood, an unrelated rant);\n"
    "  (c) is about something OUTSIDE THE HOST'S CONTROL — circumstances the host "
    "cannot reasonably influence (airport delays, weather, a city-wide power cut, "
    "or shared/communal facilities the host does not operate);\n"
    "  (d) violates Airbnb's CONTENT POLICY — discriminatory, threatening, profane, "
    "or contains private/personal information;\n"
    "  (e) is from a guest who CANCELLED before the stay, or a fraudulent booking.\n\n"
    "REMOVABILITY RUBRIC (map the review to the grounds above):\n"
    "• HIGH = clearly matches (a),(c),(d), or (e): extortion/threats, content "
    "unrelated to the stay, discrimination/profanity, out-of-host-control factors, "
    "or guest cancelled and still reviewed.\n"
    "• MEDIUM = grey area under (a),(b), or (c): very brief content-less reviews, "
    "third-party complaints, evidenceable factual errors, single-issue biased "
    "complaints.\n"
    "• LOW = legitimate complaint about a real issue inside the host's control "
    "(cleanliness, AC, water heater, wifi, the code/entry, amenities) → CANNOT be "
    "removed; respond publicly instead.\n\n"
    "PARKING — IMPORTANT: Ouja does NOT control parking. Parking is shared/communal "
    "and managed by the compound or building, not by us. So:\n"
    "  • For removability: a complaint ONLY about parking availability is "
    "OUTSIDE THE HOST'S CONTROL → lean MEDIUM/HIGH and cite ground (c).\n"
    "  • In the public response: NEVER claim we fixed/added/resolved parking. "
    "Instead acknowledge warmly and gently clarify that parking is managed by the "
    "compound/building and offer that our guest team can advise on the best nearby "
    "options. Do NOT promise a parking fix.\n\n"
    "DISPUTE MESSAGE (English) — HIGH/MEDIUM only:\n"
    "• Address Airbnb support directly, polite and concise.\n"
    "• Quote the specific policy ground (a)-(e) being violated and reference "
    "airbnb.com/help/article/2673.\n"
    "• Reference the review ID and listing if available.\n"
    "• Close: 'Thank you, Ouja Residence team.'\n\n"
    "NEGATIVE PUBLIC RESPONSE — AAA framework + Ritz-Carlton tone:\n"
    "  A1. ACKNOWLEDGE  — thank the guest by name, validate their experience.\n"
    "  A2. APOLOGIZE    — sincere apology for the specific pain point only if "
    "the complaint is legitimate; never grovel; never admit liability you don't have.\n"
    "  A3. ACT          — state that the issue HAS BEEN RESOLVED / addressed "
    "(reassuring, past tense) so future guests are covered — EXCEPT for parking or "
    "any out-of-host-control factor, where you do NOT claim a fix (see PARKING).\n"
    "• Tone: dignified, warm, ladies-and-gentlemen-serving-ladies-and-gentlemen. "
    "Never defensive, never blame the guest.\n"
    "• Length: 3–5 sentences total.\n"
    "• Close Arabic with: 'مع أطيب التحيات، فريق عوجا للسكن'\n"
    "• Close English with: 'Warm regards, OUJA RESIDENCE'\n\n"
    "DIALECT (Arabic, BOTH paths): white-Saudi/Najdi. No Egyptian, Levantine, "
    "Iraqi, or Maghrebi words. Examples of words to AVOID: دلوقتي، إيه، بدك، "
    "كمان، شو، هلق، بكير. Use: الحين، إيش، تبي، أيضاً، وش، بدري."
)

# Lightweight translator for guest review text — used when an EN-only employee
# is reading an Arabic review. Cached per review so we don't re-pay.
_REVIEW_TRANSLATE_SYSTEM = (
    "You translate Airbnb / Booking review text. Preserve tone (positive, "
    "negative, sarcastic). Return ONLY the translated text — no preamble, "
    "no quotes, no explanation. If the input is already in English, return "
    "it unchanged. If the input is empty, return an empty string."
)

def claude_translate_review_text(text, target="en"):
    """Translate review text to target lang. Returns the translated string."""
    if not text or not text.strip() or not ANTHROPIC_API_KEY:
        return text or ""
    sys_prompt = _REVIEW_TRANSLATE_SYSTEM
    if target == "en":
        user = "Translate to natural English:\n\n" + text
    else:
        user = "Translate to natural Saudi Arabic:\n\n" + text
    out = claude_text(sys_prompt, user, max_tokens=600)
    return (out or text).strip()

def claude_analyze_review(review):
    """Return the AI cache dict for a review (5 fields). Cached by review id —
    callers should check _review_ai_cache first."""
    if not ANTHROPIC_API_KEY:
        return None
    listings = get_listings_map() or {}
    unit = listings.get(review.get("listing_id"), "")
    txt = review.get("public_review") or "(empty review)"
    private = review.get("private_review") or ""
    user = (
        f"Review to analyse:\n"
        f"  ID:        {review.get('id')}\n"
        f"  Apartment: {unit or review.get('listing_id') or 'unknown'}\n"
        f"  Channel:   {review.get('channel') or 'Airbnb'}\n"
        f"  Date:      {review.get('date') or 'unknown'}\n"
        f"  Guest:     {review.get('guest_name') or 'unknown'}\n"
        f"  Rating:    {review.get('rating') or 0}/5\n"
        f"  Public review text:\n    \"{txt}\"\n"
    )
    if private:
        user += f"  Private feedback to host:\n    \"{private}\"\n"
    user += "\nReturn the JSON object now."
    out = claude_json(_REVIEW_AI_SYSTEM, user, max_tokens=1200)
    if not isinstance(out, dict):
        return None
    out["generated_at"] = datetime.now(TZ).isoformat(timespec="seconds")
    return out

