# Status -> weight for the auto progress formula (§3.6). "blocked" is special:
# excluded entirely from the calculation (not 0).
PMO_STATUS_WEIGHTS = {
    "not_started":   0,
    "in_progress":   40,
    "final_touches": 75,
    "done":          100,
}
