def _new_expense_id():
    global _expense_seq
    _expense_seq += 1
    return f"ex_{int(time.time()*1000)}_{_expense_seq:06d}"

def _new_expense_ref():
    """OJ-EXP-XXXX, auto-incrementing."""
    used = set()
    for e in _expenses.values():
        r = e.get("ref", "")
        if r.startswith("OJ-EXP-"):
            try:
                used.add(int(r.rsplit("-", 1)[-1]))
            except Exception:
                pass
    return f"OJ-EXP-{(max(used)+1 if used else 1):04d}"

def _exp_settings():
    """Defaults deep-merged with any persisted overrides."""
    s = json.loads(json.dumps(EXPENSE_DEFAULT_SETTINGS))
    for k, v in (_expense_settings or {}).items():
        s[k] = v
    return s

def _exp_norm(s):
    """Normalize an apartment name for matching (collapse spaces, lowercase)."""
    return re.sub(r"\s+", " ", str(s or "").strip()).lower()

def _exp_match_apartment(name):
    """Return (listing_id, candidates). Resolution order:
    1) an explicit Hostaway listing id in brackets/parens, e.g. "[441508] 13 JOOD"
    2) exactly one exact name match (after stripping the bracketed id)
    3) exactly one fuzzy (substring) name match
    Otherwise → candidates list for manager confirmation (or empty = not found)."""
    listings = get_listings_map() or {}
    raw = str(name or "")
    # 1) explicit listing id in [..] or (..)
    for num in re.findall(r"[\[\(]\s*(\d{3,})\s*[\]\)]", raw):
        try:
            lid = int(num)
        except ValueError:
            continue
        if lid in listings:
            return lid, []
    # strip the bracketed id for text matching
    cleaned = re.sub(r"[\[\(]\s*\d{3,}\s*[\]\)]", " ", raw)
    target = _exp_norm(cleaned)
    if not target:
        return None, []
    exact = [{"listing_id": lid, "name": nm} for lid, nm in listings.items()
             if _exp_norm(nm) == target]
    if len(exact) == 1:
        return exact[0]["listing_id"], []
    if len(exact) > 1:
        return None, exact
    # fuzzy: target contained in a listing name or vice-versa
    fuzzy = [{"listing_id": lid, "name": nm} for lid, nm in listings.items()
             if target in _exp_norm(nm) or _exp_norm(nm) in target]
    if len(fuzzy) == 1:
        return fuzzy[0]["listing_id"], []   # single confident match → resolve
    return None, fuzzy              # 0 or many → candidates (maybe empty)

def _exp_find_duplicate(exp):
    """Find an existing expense with same listing + amount + category whose
    expense_date is within the duplicate window. Returns the twin or None."""
    s = _exp_settings()
    win = int(s.get("dup_window_days") or 3)
    try:
        d0 = datetime.strptime(exp.get("expense_date", ""), "%Y-%m-%d").date()
    except Exception:
        return None
    lid = exp.get("listing_id")
    amt = exp.get("amount")
    cat = exp.get("category")
    if lid is None or amt is None:
        return None
    for other in _expenses.values():
        if other.get("id") == exp.get("id"):
            continue
        if other.get("status") in ("discarded", "failed"):
            continue
        if other.get("listing_id") != lid or other.get("amount") != amt \
           or other.get("category") != cat:
            continue
        try:
            d1 = datetime.strptime(other.get("expense_date", ""), "%Y-%m-%d").date()
        except Exception:
            continue
        if abs((d1 - d0).days) <= win:
            return other
    return None

def _exp_validate(exp):
    """Run the six checks (§C.3) in order, collect every problem, and set
    status to 'ready' or 'held' with reasons. Mutates exp in place."""
    s = _exp_settings()
    reasons = []          # list of (code, detail)
    # Check 1 — completeness
    missing = []
    if not (exp.get("submitter") or "").strip():       missing.append("submitter")
    if not (exp.get("apartment") or "").strip():       missing.append("apartment")
    if not (exp.get("maintenance_type") or "").strip(): missing.append("maintenance_type")
    if not (exp.get("category") or "").strip():        missing.append("category")
    amt = exp.get("amount")
    if not isinstance(amt, (int, float)) or amt is None: missing.append("amount")
    if not (exp.get("expense_date") or "").strip():    missing.append("expense_date")
    has_receipt = bool((exp.get("receipt_link") or "").strip())
    has_reason  = bool((exp.get("no_receipt_reason") or "").strip())
    if not has_receipt and not has_reason:             missing.append("receipt")
    if missing:
        reasons.append(("incomplete", ",".join(missing)))
    # Check 2 — apartment match
    lid, cands = _exp_match_apartment(exp.get("apartment"))
    if lid is not None:
        exp["listing_id"] = lid
        exp["candidates"] = []
    else:
        exp["listing_id"] = None
        exp["candidates"] = cands
        if cands:
            reasons.append(("apartment_confirm", ""))
        elif (exp.get("apartment") or "").strip():
            reasons.append(("apartment_none", ""))
    # Check 3 — amount sanity
    if isinstance(amt, (int, float)) and amt is not None:
        if amt <= 0:
            if ("incomplete", ) not in [(r[0],) for r in reasons]:
                reasons.append(("incomplete", "amount"))
        else:
            thr = float(s.get("high_amount_threshold") or 0)
            if thr > 0 and amt > thr and not exp.get("amount_approved"):
                reasons.append(("high_amount", str(int(amt))))
    # Check 4 — date sanity
    ds = (exp.get("expense_date") or "").strip()
    if ds:
        try:
            d = datetime.strptime(ds, "%Y-%m-%d").date()
            today = datetime.now(TZ).date()
            max_age = int(s.get("max_age_days") or 90)
            if (d > today or (today - d).days > max_age) and not exp.get("date_approved"):
                reasons.append(("bad_date", ds))
        except Exception:
            if not exp.get("date_approved"):
                reasons.append(("bad_date", ds))
    # Check 5 — receipt
    if s.get("receipt_required") and not has_receipt and has_reason and not exp.get("no_receipt_approved"):
        reasons.append(("no_receipt", ""))
    # Check 6 — possible duplicate (only meaningful once apartment+amount known)
    if exp.get("listing_id") is not None and isinstance(amt, (int, float)) and amt and amt > 0 \
       and not exp.get("dup_ignored"):
        twin = _exp_find_duplicate(exp)
        if twin:
            reasons.append(("duplicate", f"{twin.get('ref')}|{twin.get('expense_date')}"))
            exp["dup_of"] = twin.get("id")
    else:
        exp["dup_of"] = None
    exp["hold_reasons"] = [{"code": c, "detail": d} for c, d in reasons]
    if reasons:
        exp["status"] = "held"
        exp["primary_reason"] = reasons[0][0]
    else:
        exp["status"] = "ready"
        exp["primary_reason"] = None
    exp["updated_at"] = datetime.now(TZ).isoformat(timespec="seconds")
    return exp

def _exp_post_to_hostaway(exp):
    """Write a Ready expense to Hostaway. Sets posted/failed. Respects DRYRUN.
    On any error → status 'failed' with the exact message (queued for retry)."""
    if exp.get("listing_id") is None:
        exp["status"] = "failed"; exp["error"] = "no matched listing"
        return False
    s = _exp_settings()
    cat = (s.get("category_map") or {}).get(exp.get("category") or "", exp.get("category") or "Other")
    name = (exp.get("maintenance_type") or "Expense")
    if (exp.get("note") or "").strip():
        name = f"{name} — {exp['note'].strip()}"
    desc_bits = []
    if exp.get("vendor"):          desc_bits.append(f"Vendor: {exp['vendor']}")
    if exp.get("payment_method"):  desc_bits.append(f"Paid: {exp['payment_method']}")
    if exp.get("submitter"):       desc_bits.append(f"By: {exp['submitter']}")
    if exp.get("receipt_link"):    desc_bits.append(f"Receipt: {exp['receipt_link']}")
    if exp.get("no_receipt_reason"): desc_bits.append(f"No receipt: {exp['no_receipt_reason']}")
    payload = {
        "listingMapId": int(exp["listing_id"]),
        "amount": -abs(float(exp["amount"])),      # expenses are negative in Hostaway
        "expenseDate": exp.get("expense_date"),
        "date": exp.get("expense_date"),
        "categoryName": cat,
        "concept": name[:120],
        "name": name[:120],
        "description": " · ".join(desc_bits)[:900],
        "currency": "SAR",
    }
    if EXPENSE_POST_DRYRUN:
        exp["status"] = "posted"
        exp["hostaway_ref"] = "DRYRUN"
        exp["posted_at"] = datetime.now(TZ).isoformat(timespec="seconds")
        exp["posted_auto"] = True
        exp["error"] = None
        return True
    try:
        res = api_post(EXPENSE_HOSTAWAY_PATH, payload)
        ref = None
        if isinstance(res, dict):
            ref = (res.get("result") or {}).get("id") if isinstance(res.get("result"), dict) else res.get("id")
        exp["status"] = "posted"
        exp["hostaway_ref"] = str(ref) if ref is not None else "ok"
        exp["posted_at"] = datetime.now(TZ).isoformat(timespec="seconds")
        exp["posted_auto"] = True
        exp["error"] = None
        return True
    except Exception as e:
        exp["status"] = "failed"
        exp["error"] = str(e)[:400]
        return False

def _exp_process(exp, *, allow_post=True):
    """Validate, then auto-post if Ready and auto-post is enabled."""
    _exp_validate(exp)
    s = _exp_settings()
    if allow_post and exp.get("status") == "ready" and s.get("auto_post"):
        _exp_post_to_hostaway(exp)
    return exp

def _exp_ingest(sub):
    """Create one expense from a raw form submission dict. Idempotent by
    submission_id. Returns (expense, created_bool)."""
    sub_id = str(sub.get("submission_id") or "").strip()
    if sub_id:
        for e in _expenses.values():
            if e.get("submission_id") == sub_id:
                return e, False
    amt = sub.get("amount")
    try:
        amt = round(float(str(amt).replace(",", "").strip()), 2) if amt not in (None, "") else None
    except Exception:
        amt = None
    eid = _new_expense_id()
    exp = {
        "id": eid,
        "ref": _new_expense_ref(),
        "submission_id": sub_id or eid,
        "submitter": (sub.get("submitter") or "").strip()[:80],
        "apartment": (sub.get("apartment") or "").strip()[:120],
        "listing_id": None,
        "maintenance_type": (sub.get("maintenance_type") or "").strip()[:60],
        "category": (sub.get("category") or "").strip()[:60],
        "amount": amt,
        "expense_date": (sub.get("expense_date") or "").strip()[:10],
        "receipt_link": (sub.get("receipt_link") or "").strip()[:600],
        "no_receipt_reason": (sub.get("no_receipt_reason") or "").strip()[:200],
        "vendor": (sub.get("vendor") or "").strip()[:120],
        "payment_method": (sub.get("payment_method") or "").strip()[:40],
        "note": (sub.get("note") or "").strip()[:300],
        "submitted_at": (sub.get("submitted_at") or datetime.now(TZ).isoformat(timespec="seconds")),
        "status": "captured",
        "hold_reasons": [], "primary_reason": None, "candidates": [],
        "dup_of": None, "hostaway_ref": None, "posted_at": None,
        "posted_auto": False, "error": None,
        "created_at": datetime.now(TZ).isoformat(timespec="seconds"),
    }
    _expenses[eid] = exp
    _exp_process(exp)
    return exp, True

def _exp_sheet_csv_candidates():
    """From the configured link, build a list of CSV URLs to try in order.
    Handles the common gid mismatch (a sheet's first tab is rarely gid=0) by also
    trying without gid and via the gviz endpoint."""
    u = EXPENSE_SHEET_CSV_URL
    if not u:
        return []
    if "output=csv" in u or "tqx=out:csv" in u or u.endswith(".csv"):
        return [u]
    m = re.search(r"/spreadsheets/d/(?:e/)?([A-Za-z0-9_-]+)", u)
    if not m:
        return [u]
    sid = m.group(1)
    base = f"https://docs.google.com/spreadsheets/d/{sid}"
    g = re.search(r"[#&?]gid=(\d+)", u)
    gid = g.group(1) if g else None
    cands = []
    if gid:
        cands.append(f"{base}/export?format=csv&gid={gid}")
        cands.append(f"{base}/gviz/tq?tqx=out:csv&gid={gid}")
    cands.append(f"{base}/export?format=csv")            # default = first sheet
    cands.append(f"{base}/gviz/tq?tqx=out:csv")
    return cands

def _exp_sheet_csv_url():
    cands = _exp_sheet_csv_candidates()
    return cands[0] if cands else ""

def _exp_fetch_sheet(timeout=20):
    """Try each candidate URL until one returns real CSV (not an HTML page).
    Returns dict {text, url, status, content_type, bytes, error}."""
    out = {"text": None, "url": "", "status": None, "content_type": "",
           "bytes": 0, "error": None}
    cands = _exp_sheet_csv_candidates()
    if not cands:
        out["error"] = "EXPENSE_SHEET_CSV_URL not set on Railway"
        return out
    last = None
    for url in cands:
        try:
            r = requests.get(url, timeout=timeout, allow_redirects=True)
            ct = r.headers.get("Content-Type", "")
            body = r.content or b""
            txt = body.decode("utf-8-sig", errors="replace")
            head = txt.lstrip()[:200].lower()
            is_html = head.startswith("<!doctype") or head.startswith("<html") or "<head" in head
            last = {"text": txt, "url": url, "status": r.status_code,
                    "content_type": ct, "bytes": len(body),
                    "error": None if (r.ok and not is_html) else
                             ("HTTP %d / %s" % (r.status_code, "html" if is_html else "error"))}
            if r.ok and not is_html and ("," in txt or "\n" in txt):
                return last
        except Exception as e:
            last = {"text": None, "url": url, "status": None, "content_type": "",
                    "bytes": 0, "error": "fetch error: " + str(e)[:160]}
    return last or out

def _exp_parse_sheet_date(s):
    """Best-effort → YYYY-MM-DD. Handles ISO and D/M/Y or M/D/Y; manager can fix later."""
    s = str(s or "").strip()
    if not s:
        return ""
    m = re.match(r"(\d{4})-(\d{1,2})-(\d{1,2})", s)
    if m:
        return f"{m.group(1)}-{int(m.group(2)):02d}-{int(m.group(3)):02d}"
    m = re.match(r"(\d{1,2})[/.](\d{1,2})[/.](\d{4})", s)
    if m:
        a, b, y = int(m.group(1)), int(m.group(2)), m.group(3)
        if a > 12 and b <= 12:      d, mo = a, b      # clearly D/M/Y
        elif b > 12 and a <= 12:    mo, d = a, b      # clearly M/D/Y
        else:                       mo, d = a, b      # ambiguous → M/D/Y (Google Sheets default)
        return f"{y}-{mo:02d}-{int(d):02d}"
    return s[:10]

def _exp_sheet_colmap(headers):
    """Map each logical field to a column index using exact header, then fuzzy."""
    norm = [str(h or "").strip() for h in headers]
    low = [h.lower() for h in norm]
    idx = {}
    for field, want in EXPENSE_SHEET_COLS.items():
        c = next((i for i, h in enumerate(norm) if h == want), None)
        if c is None:
            for kw in EXPENSE_SHEET_FUZZY.get(field, []):
                c = next((i for i, h in enumerate(low) if kw.lower() in h), None)
                if c is not None:
                    break
        idx[field] = c
    return idx

def _exp_sheet_row_to_sub(idx, row):
    """Turn one CSV row into an ingest submission dict (or None if empty/no amount)."""
    def g(field):
        c = idx.get(field)
        return (row[c].strip() if (c is not None and c < len(row) and row[c] is not None) else "")
    ts = g("timestamp")
    submitter = g("submitter"); apartment = g("apartment"); amount = g("amount")
    if not (apartment or amount or submitter):
        return None
    receipt = g("receipt_link"); norec = g("no_receipt_reason")
    bits = []
    if g("description"): bits.append(g("description"))
    if g("notes"):       bits.append(g("notes"))
    if g("vat"):         bits.append("الضريبة/VAT: " + g("vat"))
    key = "|".join([ts, submitter, amount, apartment, g("expense_date")])
    return {
        "submission_id":     "gs-" + hashlib.sha1(key.encode("utf-8")).hexdigest()[:16],
        "submitter":         submitter,
        "apartment":         apartment,
        "maintenance_type":  g("maintenance_type"),
        "category":          EXPENSE_DEFAULT_CATEGORY,
        "amount":            amount,
        "expense_date":      _exp_parse_sheet_date(g("expense_date")),
        "receipt_link":      receipt,
        "no_receipt_reason": "" if receipt else norec,
        "vendor":            g("vendor"),
        "payment_method":    "",
        "note":              " · ".join(bits),
        "submitted_at":      ts or datetime.now(TZ).isoformat(timespec="seconds"),
    }

_exp_sheet_diag = {}     # last sheet-poll diagnostics (for troubleshooting)

def _exp_poll_sheet():
    """Fetch the shared Google Sheet as CSV and ingest any new rows. Idempotent
    (rows dedupe by a stable submission_id). Returns count of newly-created expenses.
    Records why it got nothing into _exp_sheet_diag for the reconcile/debug view."""
    global _exp_sheet_diag
    diag = {"configured": bool(EXPENSE_SHEET_CSV_URL), "resolved_url": "",
            "http_status": None, "content_type": "", "bytes": 0,
            "rows_parsed": 0, "data_rows": 0, "headers": [], "mapped": {},
            "looks_like_html": False, "error": None, "created": 0}
    if not EXPENSE_SHEET_CSV_URL:
        diag["error"] = "EXPENSE_SHEET_CSV_URL not set on Railway"
        _exp_sheet_diag = diag
        return 0
    fetched = _exp_fetch_sheet(timeout=30)
    diag["resolved_url"] = fetched.get("url", "")
    diag["http_status"] = fetched.get("status")
    diag["content_type"] = fetched.get("content_type", "")
    diag["bytes"] = fetched.get("bytes", 0)
    text = fetched.get("text")
    if not text:
        diag["error"] = fetched.get("error") or "no data returned"
        _exp_sheet_diag = diag
        print("expense sheet poll: fetch error:", diag["error"])
        return 0
    head = text.lstrip()[:200].lower()
    diag["looks_like_html"] = head.startswith("<!doctype") or head.startswith("<html") or "<head" in head
    import csv as _csv, io as _io
    rows = list(_csv.reader(_io.StringIO(text)))
    diag["rows_parsed"] = len(rows)
    if diag["looks_like_html"]:
        diag["error"] = "got an HTML page, not CSV — the sheet is probably not shared 'Anyone with the link'"
    if len(rows) < 2:
        if not diag["error"]:
            diag["error"] = "no data rows (only %d row[s])" % len(rows)
        _exp_sheet_diag = diag
        return 0
    diag["headers"] = [str(h).strip() for h in rows[0]][:30]
    idx = _exp_sheet_colmap(rows[0])
    diag["mapped"] = {k: (v is not None) for k, v in idx.items()}
    created = 0; data_rows = 0
    for raw in rows[1:]:
        if not any(str(c).strip() for c in raw):
            continue
        data_rows += 1
        sub = _exp_sheet_row_to_sub(idx, raw)
        if not sub:
            continue
        try:
            _exp, was_new = _exp_ingest(sub)
            if was_new:
                created += 1
        except Exception as e:
            print("expense sheet poll: ingest error:", e)
    diag["data_rows"] = data_rows
    diag["created"] = created
    _exp_sheet_diag = diag
    if created:
        persist_state()
        log_event("ops", f"مصاريف الميدان · استورد {created} مصروف جديد من الشيت")
    return created

def _exp_sheet_probe():
    """Sheet-only diagnostic: fetch + parse the CSV and report what we see.
    Does NOT ingest and does NOT touch Hostaway, so it returns fast and can't hang."""
    diag = {"configured": bool(EXPENSE_SHEET_CSV_URL), "resolved_url": "",
            "http_status": None, "content_type": "", "bytes": 0, "rows_parsed": 0,
            "data_rows": 0, "headers": [], "mapped": {}, "sample": None,
            "looks_like_html": False, "error": None}
    if not EXPENSE_SHEET_CSV_URL:
        diag["error"] = "EXPENSE_SHEET_CSV_URL not set on Railway"
        return diag
    fetched = _exp_fetch_sheet(timeout=20)
    diag["resolved_url"] = fetched.get("url", "")
    diag["http_status"] = fetched.get("status")
    diag["content_type"] = fetched.get("content_type", "")
    diag["bytes"] = fetched.get("bytes", 0)
    text = fetched.get("text")
    if not text:
        diag["error"] = fetched.get("error") or "no data returned"
        return diag
    head = text.lstrip()[:200].lower()
    diag["looks_like_html"] = head.startswith("<!doctype") or head.startswith("<html") or "<head" in head
    if diag["looks_like_html"]:
        diag["error"] = "got an HTML page, not CSV — the sheet is probably not shared 'Anyone with the link'"
    import csv as _csv, io as _io
    rows = list(_csv.reader(_io.StringIO(text)))
    diag["rows_parsed"] = len(rows)
    if rows:
        diag["headers"] = [str(h).strip() for h in rows[0]][:30]
        idx = _exp_sheet_colmap(rows[0])
        diag["mapped"] = {k: (v is not None) for k, v in idx.items()}
        data = [rr for rr in rows[1:] if any(str(c).strip() for c in rr)]
        diag["data_rows"] = len(data)
        if data:
            sub = _exp_sheet_row_to_sub(idx, data[0])
            if sub:
                diag["sample"] = {"apartment": sub.get("apartment"), "amount": sub.get("amount"),
                                  "date": sub.get("expense_date"), "submitter": sub.get("submitter")}
    if not diag["error"] and diag["data_rows"] == 0:
        diag["error"] = "no data rows found"
    return diag

def _exp_hostaway_probe():
    """Diagnostic: try the configured expenses path AND a few likely alternates,
    reporting status/shape/count so we can confirm the right Hostaway endpoint."""
    candidates = [EXPENSE_HOSTAWAY_PATH, "/expenses", "/expenses/list",
                  "/listingExpenses", "/financeExpenses", "/financialReporting/expenses"]
    seen, tried = set(), []
    for path in candidates:
        if not path or path in seen:
            continue
        seen.add(path)
        entry = {"path": path, "ok": None, "raw_type": None, "keys": [],
                 "count": None, "sample": None, "error": None}
        try:
            data = api_get(path, params={"limit": 5})
            entry["ok"] = True
            entry["raw_type"] = type(data).__name__
            if isinstance(data, dict):
                entry["keys"] = list(data.keys())[:20]
                res = data.get("result")
                if isinstance(res, list):
                    entry["count"] = len(res)
                    if res:
                        entry["sample"] = str(res[0])[:600]
                else:
                    entry["count"] = "result=" + type(res).__name__
                    entry["sample"] = str(data)[:600]
            elif isinstance(data, list):
                entry["count"] = len(data)
                if data:
                    entry["sample"] = str(data[0])[:600]
        except Exception as e:
            entry["ok"] = False
            entry["error"] = str(e)[:250]
        tried.append(entry)
        # stop early if we clearly found expenses
        if entry["ok"] and isinstance(entry["count"], int) and entry["count"] > 0:
            break
    return {"configured_path": EXPENSE_HOSTAWAY_PATH, "tried": tried}

def _exp_fetch_hostaway(max_pages=10):
    """Fetch existing expenses already in Hostaway (paginated, capped). Returns
    (list, ok, error). 'ok' is False if the endpoint doesn't respond as expected."""
    items, offset, page = [], 0, 100
    try:
        for _ in range(max_pages):
            data = api_get(EXPENSE_HOSTAWAY_PATH, params={"limit": page, "offset": offset})
            batch = (data or {}).get("result")
            if batch is None and isinstance(data, list):
                batch = data
            batch = batch or []
            items.extend(batch)
            if len(batch) < page:
                break
            offset += page
        return items, True, None
    except Exception as e:
        return items, False, str(e)[:300]

def _exp_ha_key(lid, amount, date_str):
    try:
        return (int(lid), round(abs(float(amount)), 2), str(date_str or "")[:10])
    except Exception:
        return None

def _exp_reconcile(apply=False):
    """Pull every sheet row, compare against expenses already in Hostaway, and
    report (and optionally post) the clean ones that are missing from Hostaway.
    Held/incomplete/unmatched expenses are never auto-posted — they stay in the
    review queue. Respects EXPENSE_POST_DRYRUN. Returns a summary dict."""
    pulled = _exp_poll_sheet()
    # Re-run validation on every not-yet-posted expense so the latest apartment
    # matching (e.g. the bracketed listing-id rule) re-resolves old held items.
    revalidated = 0
    for e in list(_expenses.values()):
        if e.get("status") == "discarded":
            continue
        if e.get("hostaway_ref") and e["hostaway_ref"] not in ("DRYRUN", "existing", "ok", None):
            continue
        before = e.get("status")
        _exp_validate(e)
        if e.get("status") != before:
            revalidated += 1
    ha_items, ha_ok, ha_err = _exp_fetch_hostaway()
    ha_keys = set()
    for x in ha_items:
        lid = x.get("listingMapId") or x.get("listingId") or x.get("listing_id")
        k = _exp_ha_key(lid, x.get("amount"), x.get("expenseDate") or x.get("date"))
        if k:
            ha_keys.add(k)

    total = len(_expenses)
    counts = {"held": 0, "already_ours": 0, "already_in_hostaway": 0,
              "missing": 0, "posted_now": 0, "post_failed": 0, "unmatched": 0}
    missing_preview = []
    for e in _expenses.values():
        st = e.get("status")
        if st == "discarded":
            continue
        # already truly posted by us (real Hostaway ref, not a DRYRUN placeholder)
        if e.get("hostaway_ref") and e["hostaway_ref"] not in ("DRYRUN", "existing", "ok", None):
            counts["already_ours"] += 1
            continue
        # only clean/ready expenses are eligible to post; held ones wait for review
        ready = (st == "ready") or (st == "posted" and e.get("hostaway_ref") in ("DRYRUN", "ok", "existing", None))
        if not ready:
            counts["held"] += 1
            continue
        lid = e.get("listing_id")
        if lid is None:
            counts["unmatched"] += 1
            continue
        k = _exp_ha_key(lid, e.get("amount"), e.get("expense_date"))
        if ha_ok and k and k in ha_keys:
            # Hostaway already has an equivalent expense → mark as reconciled, don't repost
            e["status"] = "posted"
            if not e.get("hostaway_ref") or e["hostaway_ref"] == "DRYRUN":
                e["hostaway_ref"] = "existing"
            counts["already_in_hostaway"] += 1
            continue
        # missing from Hostaway
        counts["missing"] += 1
        missing_preview.append({"ref": e.get("ref"), "apartment": e.get("apartment"),
                                "amount": e.get("amount"), "date": e.get("expense_date"),
                                "type": e.get("maintenance_type")})
        if apply:
            ok = _exp_post_to_hostaway(e)
            counts["posted_now" if ok else "post_failed"] += 1
    persist_state()
    summary = {"pulled_from_sheet": pulled, "total_expenses": total,
               "revalidated": revalidated,
               "hostaway_fetch_ok": ha_ok, "hostaway_error": ha_err,
               "hostaway_existing": len(ha_keys), "dryrun": EXPENSE_POST_DRYRUN,
               "applied": bool(apply), **counts,
               "missing_sample": missing_preview[:50],
               "sheet_debug": dict(_exp_sheet_diag)}
    log_event("ops", f"مطابقة المصاريف · سحب {pulled} · ناقص {counts['missing']} · "
                     f"{'رُحّل ' + str(counts['posted_now']) if apply else 'معاينة'}")
    return summary

# ===================== QUOTATIONS (عرض سعر) =====================
# Print-ready quotes for clients. Each one has line items + service-fee % +
# VAT toggle + signature. Modelled on the standalone HTML the owner sent.
_quotes = {}   # quote_id -> dict
_QUOTE_SEQ = 0
_unit_owners = {}   # apartment name -> owner name (item 60: per-owner P&L)
_finance_defaults = {}   # report key (owner name or 'lid:N') -> saved report fields (Stage 3 item 16)

def _new_quote_id():
    global _QUOTE_SEQ
    _QUOTE_SEQ += 1
    return f"q_{int(time.time()*1000)}_{_QUOTE_SEQ:04d}"

def _new_quote_number():
    """OJ-YYYYMM-XXX (auto-incrementing seq within the month)."""
    now = datetime.now(TZ)
    prefix = f"OJ-{now.year}{now.month:02d}-"
    used = set()
    for q in _quotes.values():
        n = q.get("number", "")
        if n.startswith(prefix):
            try:
                used.add(int(n.rsplit("-", 1)[-1]))
            except Exception:
                pass
    nxt = max(used) + 1 if used else 1
    return f"{prefix}{nxt:03d}"

# ===================== USERS + ROLE-BASED PERMISSIONS =====================
# Multi-user system layered on top of the legacy DASHBOARD_TOKEN. The legacy
# token still works as a super-admin backdoor (for the owner). Anyone else
# logs in with username + password → gets a session token stored client-side.
#
# Each user has:
#   id          "u_<ts><rand>"
#   name        display name (also used as login username)
#   password_hash  PBKDF2 SHA-256, 100k rounds, salted
#   role        "admin" | "ops" | "viewer"  (preset, but perms override)
#   perms       per-tab matrix {tab: {read, write, create}}
#   active      bool — disabled users can't log in
#   created_at  ISO
#   created_by  who added them
_users = {}                 # user_id -> user dict
_sessions = {}              # session_token -> {user_id, expires_at}

_USER_TABS = [
    "home", "inbox", "today", "calendar", "pricing", "strat", "clean",
    "tickets", "reviews", "guests", "quality", "rev", "learn", "log",
    "users", "quote", "weekly", "design", "pmo", "expenses", "listings",
]

def _default_perms(role):
    """Build the starting permission matrix for a role."""
    if role == "admin":
        return {tab: {"read": True, "write": True, "create": True} for tab in _USER_TABS}
    if role == "ops":
        # ops can see + modify most things, but only create tickets/quotes
        return {
            tab: {
                "read":   tab != "users",
                "write":  tab not in ("users", "rev", "log"),
                "create": tab in ("tickets", "quote", "weekly", "design"),
            } for tab in _USER_TABS
        }
    # viewer: read-only on everything except admin tabs
    return {
        tab: {"read": tab not in ("users",), "write": False, "create": False}
        for tab in _USER_TABS
    }

def _hash_password(pw):
    salt = _secrets_mod.token_hex(16)
    h = hashlib.pbkdf2_hmac("sha256", pw.encode("utf-8"), salt.encode("utf-8"), 100_000)
    return f"{salt}${h.hex()}"

def _verify_password(pw, stored):
    try:
        salt, hexed = stored.split("$", 1)
        new = hashlib.pbkdf2_hmac("sha256", pw.encode("utf-8"),
                                  salt.encode("utf-8"), 100_000)
        # constant-time compare
        return hashlib.sha256(new.hex().encode()).digest() == hashlib.sha256(hexed.encode()).digest()
    except Exception:
        return False

def _new_user_id():
    return f"u_{int(time.time()*1000)}_{random.randint(100,999)}"

def _new_session_token():
    return _secrets_mod.token_urlsafe(32)

def _user_create(name, password, role="viewer", perms=None, created_by="system"):
    """Create a new user. Returns the user dict (without the password hash)."""
    uid = _new_user_id()
    u = {
        "id": uid,
        "name": (name or "").strip(),
        "password_hash": _hash_password(password or ""),
        "role": role if role in ("admin", "ops", "viewer") else "viewer",
        "perms": perms or _default_perms(role),
        "active": True,
        "created_at": datetime.now(TZ).isoformat(timespec="seconds"),
        "created_by": created_by or "system",
    }
    _users[uid] = u
    return u

def _user_view(u):
    """Public view (no password hash)."""
    if not u:
        return None
    return {k: v for k, v in u.items() if k != "password_hash"}

def _find_user_by_name(name):
    if not name:
        return None
    name = name.strip().lower()
    for u in _users.values():
        if (u.get("name") or "").strip().lower() == name:
            return u
    return None

def _auth_session(request):
    """Look up the session by token. Returns the user dict (full) or None."""
    token = request.query.get("token", "") or request.headers.get("X-Token", "")
    if not token:
        return None
    sess = _sessions.get(token)
    if not sess:
        return None
    if sess.get("expires_at", 0) < time.time():
        _sessions.pop(token, None)
        return None
    u = _users.get(sess.get("user_id"))
    if not u or not u.get("active"):
        return None
    return u

def _user_can(request, tab, action="read"):
    """Permission check. Legacy DASHBOARD_TOKEN is treated as super-admin."""
    token = request.query.get("token", "") or request.headers.get("X-Token", "")
    if DASHBOARD_TOKEN and hmac.compare_digest(token, DASHBOARD_TOKEN):
        return True
    u = _auth_session(request)
    if not u:
        return False
    if u.get("role") == "admin":
        return True
    return bool(((u.get("perms") or {}).get(tab) or {}).get(action))

# ===================== REVIEWS (Hostaway + AI dispute/AAA) =====================
# Per review:
#   id          str (Hostaway review id)
#   listing_id  int
#   rating      int 1..5 (Hostaway returns 0-10 — we /2 round)
#   guest_name  str
#   public_review str (the guest's actual text)
#   private_review str (private feedback, if any)
#   date        ISO date of stay/review
#   channel     "Airbnb" | "Booking" | ...
#   is_public   bool
# AI cache keyed by review id:
#   removability: "high"|"medium"|"low"
#   removability_reason_ar: str
#   dispute_angle_ar: str
#   dispute_message_en: str
#   public_response_ar: str (Ritz-Carlton + AAA)
#   public_response_en: str (Ritz-Carlton + AAA)
#   generated_at: ISO timestamp
# Review state (manual annotations):
#   fixed: bool          (team has resolved the underlying issue)
#   assignee: str | None
#   notes: str
#   ticket_id: str | None  (if a maintenance ticket was opened from this review)
#   last_edit_by: str
#   last_edit_at: ISO
_reviews = {}            # rev_id -> raw review dict
_review_ai_cache = {}    # rev_id -> AI analysis dict
_review_states = {}      # rev_id -> manual state dict
_review_translations = {}  # rev_id -> {"en": "...", "ar": "..."} cached translations
_reviews_last_fetch = 0  # epoch seconds
# Live progress for the "analyze everything now" bulk job (one at a time).
_review_bulk_job = {"running": False, "total": 0, "done": 0, "errors": 0,
                    "started": 0, "finished": 0}

# Historical review analytics, baked from the Airbnb/Hostaway export
# (reviews_insights.json, shipped in the repo). Holds per-apartment category
# averages + common-issue tags that the live /v1/reviews feed doesn't expose.
_reviews_insights = {}

def load_reviews_insights():
    """Load the shipped historical-insights file (sits next to bot.py, NOT in
    STATE_DIR). Safe to call repeatedly; missing file just means no history."""
    global _reviews_insights
    try:
        path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "reviews_insights.json")
        with open(path, encoding="utf-8") as f:
            _reviews_insights = json.load(f) or {}
    except FileNotFoundError:
        _reviews_insights = {}
    except Exception as e:
        print("load_reviews_insights error:", e)
        _reviews_insights = {}
    return _reviews_insights

load_reviews_insights()

# Owner's chosen "queue start" anchor. Set by /api/cleaning/reschedule-from and
# also auto-applied after pause/unpause so the queue stays compacted forward.
# If today drifts past the anchor, we use today+1 (next valid day) instead.
_dc_anchor_date = None

def log_event(category, text):
    """Record something the bot did, for the dashboard's activity feed."""
    try:
        _activity.append({"ts": datetime.now(TZ).isoformat(timespec="seconds"),
                          "cat": category, "text": str(text)[:300]})
    except Exception:
        pass
    print(f"[{category}] {text}")

