       +   '<div style="background:var(--gold);color:#fff;width:28px;height:28px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:700;flex:0 0 28px">'+n+'</div>'
       +   '<div style="flex:1;min-width:0">'
