def _dash_auth(request):
    """Returns True if the request carries either:
      • the legacy super-admin DASHBOARD_TOKEN, OR
      • a valid (non-expired, active-user) session token from the users system.
    Both are checked against `?token=...` query param OR the X-Token header."""
    token = request.query.get("token") or request.headers.get("X-Token", "")
    if not token:
        return False
    if DASHBOARD_TOKEN and hmac.compare_digest(token, DASHBOARD_TOKEN):
        return True
    # Session token check
    sess = _sessions.get(token)
    if not sess:
        return False
    if sess.get("expires_at", 0) < time.time():
        _sessions.pop(token, None)
        return False
    u = _users.get(sess.get("user_id"))
    return bool(u and u.get("active"))

def _json(data, status=200):
    return web.json_response(data, status=status,
                             dumps=lambda o: json.dumps(o, ensure_ascii=False))

def _cache_get(key):
    hit = _dash_cache.get(key)
    return hit[0] if hit else None

_cache_inflight = set()

def _kick_compute(key, compute_fn):
    """Lazy warm: if `key` isn't cached and no compute is already running, start one
    in the background. This guarantees a page request triggers the computation even if
    the periodic cache loop is slow or hasn't run yet. Errors are cached (briefly) so
    the page shows the real problem instead of spinning forever."""
    if _cache_get(key) is not None or key in _cache_inflight:
        return
    _cache_inflight.add(key)
    async def _runner():
        try:
            val = await asyncio.to_thread(compute_fn)
            _dash_cache[key] = (val, time.time())
        except Exception as e:
            print(f"lazy {key} compute error:", e)
            _dash_cache[key] = ({"error": str(e)[:300]}, time.time())
        finally:
            _cache_inflight.discard(key)
    asyncio.create_task(_runner())

def _live_counts():
    return {"pending_cards": len(_pending_replies),
            "open_escalations": sum(1 for e in _escalations.values() if not e.get("claimed_by"))}

def fetch_inhouse(day):
    """Reservations overlapping `day` (arrived on/before, departing on/after) — a precise,
    bounded query (~one row per occupied/turning unit) so occupancy is always accurate."""
    try:
        data = api_get("/reservations", params={
            "arrivalEndDate": day.isoformat(),          # arrivalDate <= today
            "departureStartDate": day.isoformat(),      # departureDate >= today
            "limit": 200})
        return data.get("result", []) or []
    except Exception as e:
        print("in-house fetch error:", e)
        return []

def _compute_today():
    """The morning cockpit: arrivals, departures, who's empty tonight, same-day turnovers,
    and the revenue on the table. Occupancy comes from a targeted in-house query (accurate)."""
    today = datetime.now(TZ).date()
    listings = get_listings_map()
    rows = fetch_inhouse(today)
    if not rows:                                            # fallback to history if the query fails
        rows = [r for r in get_reservations_cached() if _res_realized(r)]
    print(f"today: in-house query returned {len(rows)} reservations")

    def nm(r):
        return listings.get(r.get("listingMapId")) or r.get("listingName") or f"unit-{r.get('listingMapId')}"

    arrivals, departures = [], []
    occ_lids, dep_lids, arr_lids = set(), set(), set()
    for r in rows:
        if not _res_realized(r):
            continue
        a, d = _parse_date(r.get("arrivalDate")), _parse_date(r.get("departureDate"))
        lid = r.get("listingMapId")
        if a == today:
            arrivals.append({"guest": r.get("guestName") or "Guest", "unit": nm(r),
                             "nights": _res_nights(r), "checkout": d.isoformat() if d else ""})
            arr_lids.add(lid)
        if d == today:
            departures.append({"guest": r.get("guestName") or "Guest", "unit": nm(r)})
            dep_lids.add(lid)
        if a and d and a <= today < d:
            occ_lids.add(lid)
    units = {u["id"]: u["name"] for u in _catalog_units if u.get("id")}
    active = len(units) or len(occ_lids)
    empty = [{"unit": units.get(lid, str(lid)), "lid": lid}
             for lid in units if lid not in occ_lids]
    tight = [units.get(lid, str(lid)) for lid in (dep_lids & arr_lids)]      # same-day turnover
    # Item 3: a guest arrives TODAY into a unit that still has an OPEN maintenance ticket.
    _open_by_lid = {}
    for _tk in _tickets:
        if _tk.get("status") in ("open", "in_progress") and _tk.get("lid") is not None:
            _open_by_lid.setdefault(_tk["lid"], []).append(_tk)
    arr_tickets = []
    for _lid in arr_lids:
        _tks = _open_by_lid.get(_lid)
        if _tks:
            arr_tickets.append({"unit": units.get(_lid, str(_lid)), "lid": _lid,
                                "title": _tks[0].get("title", ""), "ticket_id": _tks[0].get("id"),
                                "n": len(_tks)})
    prices = [u.get("price") for u in _catalog_units if u.get("price")]
    avg = round(sum(prices) / len(prices)) if prices else 0
    return {"date": today.isoformat(), "active": active, "occupied": len(occ_lids),
            "arr_tickets": arr_tickets,
            "arrivals": sorted(arrivals, key=lambda x: x["unit"]),
            "departures": sorted(departures, key=lambda x: x["unit"]),
            "empty": sorted(empty, key=lambda x: x["unit"])[:90], "empty_n": len(empty),
            "tight": tight, "avg": avg, "risk": len(empty) * avg,
            "pending_cards": len(_pending_replies),
            "open_escalations": sum(1 for e in _escalations.values() if not e.get("claimed_by"))}

def _compute_overview():
    today = datetime.now(TZ).date()
    reservations = get_reservations_cached()
    listings = get_listings_map()
    factors = compute_demand_factors(reservations)
    lw = compute_last_week(reservations, listings, factors)
    nights, _ = _explode_nights(reservations)
    d30 = today - timedelta(days=30)
    rev30 = sum(nl for _, d, nl in nights if d30 <= d < today)
    n30 = sum(1 for _, d, _2 in nights if d30 <= d < today)
    active = len(_catalog_units) or len(set(lid for lid, _, _2 in nights))
    occ30 = (n30 / (active * 30)) if active else 0
    ci = sum(1 for r in reservations if _res_realized(r) and _parse_date(r.get("arrivalDate")) == today)
    co = sum(1 for r in reservations if _res_realized(r) and _parse_date(r.get("departureDate")) == today)
    return {"active_units": active, "occ_30": round(occ30 * 100), "rev_30": round(rev30),
            "rev_7": round(lw["tot_rev"]), "occ_7": round(lw["occ"] * 100),
            "missed_7": round(lw["tot_missed"]), "pending_cards": len(_pending_replies),
            "open_escalations": sum(1 for e in _escalations.values() if not e.get("claimed_by")),
            "checkins_today": ci, "checkouts_today": co}

# ===================== FINANCE: monthly owner/investor report math =====================
# Stage 3 (items 13-14). PURE, source-agnostic functions so the math is exactly testable
# and never touches a number it didn't receive. NORMALIZED input rows:
#   reservation: {id, source:'hostaway'|'sheet', channel:'airbnb'|'direct', lid, apartment,
#                 checkin('YYYY-MM-DD'), checkout, nights, status, airbnb_payout:float|None,
#                 direct_revenue:float|None, refund:float, extras:float}
#   expense:     {id, apartment, lid, amount:float, date, matched:bool}
# GUARANTEE: an Airbnb reservation with airbnb_payout=None is reported as MISSING (never
# estimated) and the reconciliation refuses to balance while any are missing.
_REPORT_CANCELLED = {"cancelled", "canceled", "declined", "expired", "denied"}
FINANCE_DEFAULTS = {
    "direct_fee_pct": 3.0,        # the 3% applies to DIRECT reservations ONLY
    "period_basis": "checkin",    # CONFIRMED by Faisal
    "rounding": 2,                # [CONFIRM] default 2 decimals
    "vat_pct": 0.0,               # [CONFIRM] default none — all figures net
}

def _finance_in_period(row, start, end, basis):
    d = _parse_date(row.get("checkin" if basis == "checkin" else "checkout"))
    return d is not None and start <= d <= end

def compute_owner_report(reservations, expenses, start, end, management_pct, settings=None):
    """EXACT money math for one apartment/owner over [start, end] (item 13) + the
    reconciliation check (item 14). Pure — verifiable on synthetic data. Never estimates."""
    s = dict(FINANCE_DEFAULTS); s.update(settings or {})
    basis = s["period_basis"]; rnd = int(s["rounding"]); direct_fee = float(s["direct_fee_pct"]) / 100.0
    def R(x):
        return round(float(x), rnd) if rnd and rnd > 0 else float(round(float(x)))

    inc_airbnb = 0.0; inc_direct = 0.0; extras_total = 0.0
    resv_lines = []; missing_payout = []; needs_rule = []
    for r in reservations:
        status = (r.get("status") or "").lower()
        if status in _REPORT_CANCELLED:                       # EXCLUDE cancelled
            continue
        if status not in CONFIRMED_STATUSES:                  # only confirmed/realized
            continue
        if not _finance_in_period(r, start, end, basis):
            continue
        refund = float(r.get("refund") or 0)
        ext = float(r.get("extras") or 0); extras_total += ext
        channel = (r.get("channel") or "").lower()
        if channel == "airbnb":
            payout = r.get("airbnb_payout")
            if payout is None:                                # NEVER guess a payout
                missing_payout.append(r.get("id")); income = None
            else:
                income = float(payout) - refund               # actual amount received
                inc_airbnb += income
        elif channel == "direct":
            income = (float(r.get("direct_revenue") or 0) - refund) * (1.0 - direct_fee)  # 3% on DIRECT only
            inc_direct += income
        else:                                                 # 'other' (Booking.com, Vrbo…) — no confirmed rule
            needs_rule.append(r.get("id")); income = None     # flagged, NEVER guessed
        resv_lines.append({
            "id": r.get("id"), "channel": channel, "apartment": r.get("apartment"),
            "checkin": r.get("checkin"), "checkout": r.get("checkout"), "nights": r.get("nights"),
            "refund": R(refund), "extras": R(ext), "income": (None if income is None else R(income)),
            "gross": (r.get("airbnb_payout") if channel == "airbnb" else r.get("direct_revenue")),
        })

    total_income = inc_airbnb + inc_direct + extras_total
    ouja_fee = (float(management_pct) / 100.0) * total_income  # mgmt% BEFORE expenses
    exp_lines = [e for e in expenses if e.get("matched")
                 and _finance_in_period({"checkin": e.get("date"), "checkout": e.get("date")}, start, end, "checkin")]
    expenses_total = sum(float(e.get("amount") or 0) for e in exp_lines)
    owner_net = total_income - ouja_fee - expenses_total

    # ---- reconciliation (item 14): totals must equal the sum of the rows, to the riyal ----
    rows_income = sum((l["income"] or 0) for l in resv_lines) + extras_total
    gap = R(rows_income) - R(total_income)
    balanced = (abs(gap) < 0.005) and not missing_payout and not needs_rule
    return {
        "currency": "SAR", "period": {"start": start.isoformat(), "end": end.isoformat(), "basis": basis},
        "income_airbnb": R(inc_airbnb), "income_direct": R(inc_direct), "extras": R(extras_total),
        "total_income": R(total_income), "management_pct": float(management_pct),
        "ouja_fee": R(ouja_fee), "expenses": R(expenses_total), "owner_net": R(owner_net),
        "counts": {"reservations": len(resv_lines), "expenses": len(exp_lines)},
        "resv_lines": resv_lines, "exp_lines": exp_lines,
        "reconciliation": {"balanced": balanced, "gap": R(gap), "missing_payout_ids": missing_payout,
                           "needs_channel_rule_ids": needs_rule},
        "settings": s,
    }

# ---- Hostaway → normalized finance rows (Stage 1: ALL reservations come from Hostaway) ----
# The ACTUAL Airbnb host payout (net of Airbnb's service fee). Hostaway's standard field is
# airbnbExpectedPayoutAmount; we try a few known aliases. We NEVER fall back to totalPrice
# (that's the gross guest total, not the owner payout) — a missing payout stays None and is
# surfaced by the reconciliation, never estimated. [CONFIRM the exact field from one live
# reservation — REVENUE_DEBUG already logs 'reservation sample keys' on Railway.]
_AIRBNB_PAYOUT_FIELDS = ("airbnbExpectedPayoutAmount", "expectedPayoutAmount",
                         "ownerPayout", "hostPayout")

def _finance_channel(r):
    ch = (r.get("channelName") or r.get("channel") or "").strip().lower()
    if "airbnb" in ch:
        return "airbnb"
    if (not ch) or any(w in ch for w in ("direct", "manual", "website", "owner", "walk")):
        return "direct"
    return "other"   # Booking.com / Vrbo / etc. — NOT 'direct'; flagged for an explicit rule

def _airbnb_payout(r):
    for k in _AIRBNB_PAYOUT_FIELDS:
        v = r.get(k)
        if isinstance(v, (int, float)) and v > 0:
            return float(v)
        if isinstance(v, str):
            try:
                fv = float(v)
                if fv > 0:
                    return fv
            except Exception:
                pass
    return None

def normalize_reservation(r, listings=None):
    """One raw Hostaway reservation → a normalized finance row for compute_owner_report."""
    listings = listings or {}
    lid = r.get("listingMapId")
    ch = _finance_channel(r)
    refund = r.get("refundAmount")
    tp = r.get("totalPrice")
    return {
        "id": r.get("id") or r.get("reservationId"),
        "source": "hostaway", "channel": ch, "lid": lid,
        "apartment": listings.get(lid) or r.get("listingName") or (f"unit-{lid}" if lid else ""),
        "checkin": r.get("arrivalDate"), "checkout": r.get("departureDate"),
        "nights": _res_nights(r), "status": (r.get("status") or "").lower(),
        "airbnb_payout": (_airbnb_payout(r) if ch == "airbnb" else None),
        "direct_revenue": (float(tp) if (ch == "direct" and isinstance(tp, (int, float))) else None),
        "refund": (float(refund) if isinstance(refund, (int, float)) and refund > 0 else 0.0),
        "extras": 0.0,
    }

def build_owner_report(lid, start, end, management_pct, settings=None, expenses=None):
    """Stage 3 wiring: pull this unit's Hostaway reservations + matched expenses and run the
    verified math. lid=None → portfolio-wide. Never invents a number."""
    listings = get_listings_map() or {}
    resv = [normalize_reservation(r, listings) for r in get_reservations_cached()
            if lid is None or r.get("listingMapId") == lid]
    if expenses is None:
        expenses = []
        for e in _expenses.values():
            if e.get("status") == "posted" and (lid is None or e.get("listing_id") == lid):
                expenses.append({"id": e.get("id"), "apartment": e.get("apartment"),
                                 "lid": e.get("listing_id"), "amount": e.get("amount"),
                                 "date": e.get("expense_date"), "matched": True})
    rep = compute_owner_report(resv, expenses, start, end, management_pct, settings)
    rep["apartment"] = (listings.get(lid) if lid is not None else None)
    rep["lid"] = lid
    return rep

def _compute_revenue():
    reservations = get_reservations_cached()
    listings = get_listings_map()
    rep = compute_revenue_report(reservations, listings)
    nights, _ = _explode_nights(reservations)
    series = {}
    for _, d, nl in nights:
        series[f"{d.year}-{d.month:02d}"] = series.get(f"{d.year}-{d.month:02d}", 0) + nl
    monthly = [{"m": k, "rev": round(series[k])} for k in sorted(series)[-12:]]
    # per-unit 90-day revenue, for the per-unit P&L join in Expenses (item 59)
    today = datetime.now(TZ).date()
    d90 = today - timedelta(days=90)
    rev_by_name = {}
    for lid, d, nl in nights:
        if d >= d90:
            nm = listings.get(lid) or ""
            if nm:
                rev_by_name[nm] = rev_by_name.get(nm, 0) + nl
    # compound (neighbourhood) per unit, from the catalog (item 66)
    nb_map = {u.get("name"): (u.get("neighbourhood") or u.get("area") or "")
              for u in _catalog_units if u.get("name")}
    units = [{"name": u["name"], "compound": nb_map.get(u["name"], ""),
              "occ": round(u["occ90"] * 100), "rev90": round(rev_by_name.get(u["name"], 0)),
              "adr": round(u["adr"]) if u["adr"] else 0, "pace": round((u["pace30"] or 0) * 100),
              "reco": u["reco"], "label": u["label"]} for u in rep["units"]]
    # Item 66: per-compound aggregation (avg occupancy + ADR + unit count).
    comp = {}
    for u in units:
        c = u["compound"] or "—"
        g = comp.setdefault(c, {"compound": c, "units": 0, "occ_sum": 0, "adr_sum": 0, "adr_n": 0})
        g["units"] += 1
        g["occ_sum"] += u["occ"]
        if u["adr"]:
            g["adr_sum"] += u["adr"]; g["adr_n"] += 1
    compounds = [{"compound": g["compound"], "units": g["units"],
                  "occ": round(g["occ_sum"] / g["units"]) if g["units"] else 0,
                  "adr": round(g["adr_sum"] / g["adr_n"]) if g["adr_n"] else 0}
                 for g in comp.values()]
    compounds.sort(key=lambda x: -x["occ"])
    # Item 68: pace vs last month + same month last year (from the monthly nights-revenue series).
    today = datetime.now(TZ).date()
    _mk = lambda y, m: f"{y}-{m:02d}"
    cur = series.get(_mk(today.year, today.month), 0)
    pm_y, pm_m = (today.year, today.month - 1) if today.month > 1 else (today.year - 1, 12)
    prev_m = series.get(_mk(pm_y, pm_m), 0)
    prev_y = series.get(_mk(today.year - 1, today.month), 0)
    pace = {"cur": round(cur),
            "mom": round((cur - prev_m) / prev_m * 100) if prev_m else None,
            "yoy": round((cur - prev_y) / prev_y * 100) if prev_y else None}
    return {"monthly": monthly,
            "overall_adr": round(rep.get("overall_adr", 0) or 0),
            "compounds": compounds, "pace": pace,
            "seasonality": [{"name": m["name"], "adr": round(m["adr"]), "index": round(m["index"], 2)}
                            for m in rep["months"]],
            "salary": {str(k): round(v, 2) for k, v in rep["salary"]["dom_index"].items()},
            "weak": rep["salary"]["weak_window"], "strong": rep["salary"]["strong_window"],
            "units": units}

def _compute_calendar_grid(days=45):
    """Per-unit × per-day tape-chart grid for the next `days` days (items 10-14).
    Each cell: status (booked/empty/blocked) + nightly price + arrival/departure/orphan
    flags. Plus a per-day 'revenue at risk' total = sum of empty-night prices.
    Calendar-heavy → fetched in parallel and served from the dashboard cache."""
    today = datetime.now(TZ).date()
    end_date = today + timedelta(days=days - 1)
    listings = get_listings_map() or {}
    listing_ids = list(listings.keys())
    per_listing = {}

    def _fetch(lid):
        try:
            cal = api_get(f"/listings/{lid}/calendar",
                          params={"startDate": today.isoformat(), "endDate": end_date.isoformat()})
            return lid, (cal.get("result") or [])
        except Exception as e:
            print(f"grid cal error ({lid}):", e)
            return lid, []

    if listing_ids:
        try:
            with ThreadPoolExecutor(max_workers=INTEL_PARALLEL) as ex:
                futs = [ex.submit(_fetch, lid) for lid in listing_ids]
                for f in as_completed(futs):
                    lid, days_data = f.result()
                    per_listing[lid] = {d.get("date"): d for d in days_data if d.get("date")}
        except Exception as e:
            print("grid pool error:", e)

    date_list = [today + timedelta(days=i) for i in range(days)]
    date_isos = [d.isoformat() for d in date_list]
    at_risk = [0.0] * days
    units_out = []
    for lid in listing_ids:
        rows = per_listing.get(lid)
        if not rows:
            continue
        cells = []
        for d_iso in date_isos:
            row = rows.get(d_iso)
            if not row:
                cells.append({"status": "none", "price": None})
                continue
            booked = bool(row.get("reservationId"))
            available = int(row.get("isAvailable", 0) or 0) == 1
            price = row.get("price")
            price = round(float(price)) if isinstance(price, (int, float)) and price > 0 else None
            cells.append({"status": "booked" if booked else ("empty" if available else "blocked"),
                          "price": price})
        # Item 11: arrival/departure boundaries (from booked-run edges); Item 14: at-risk.
        for i in range(days):
            c = cells[i]
            prev_b = (i > 0 and cells[i - 1]["status"] == "booked")
            if c["status"] == "booked" and not prev_b:
                c["arr"] = 1
            if c["status"] == "empty":
                if prev_b:
                    c["dep"] = 1
                if c["price"]:
                    at_risk[i] += c["price"]
        # Item 13: orphan gaps — 1-2 empty nights wedged between two bookings.
        i = 0
        while i < days:
            if cells[i]["status"] == "empty":
                j = i
                while j < days and cells[j]["status"] == "empty":
                    j += 1
                if (j - i) <= 2 and i > 0 and cells[i - 1]["status"] == "booked" \
                   and j < days and cells[j]["status"] == "booked":
                    for k in range(i, j):
                        cells[k]["orphan"] = 1
                i = j
            else:
                i += 1
        units_out.append({"lid": lid, "name": listings.get(lid) or str(lid), "cells": cells})
    units_out.sort(key=lambda u: u["name"])
    days_out = [{"date": date_isos[i], "weekday": d.weekday(),
                 "weekend": d.weekday() in WEEKEND_DAYS,
                 "at_risk": round(at_risk[i]),
                 "events": [e["name"] for e in events_for_date(d)]}
                for i, d in enumerate(date_list)]
    return {"start": today.isoformat(), "days_count": days,
            "days": days_out, "units": units_out}

# =====================================================================
# PRICING ENGINE v2 ("فرص التسعير") — LEARNED FROM OUR OWN HOSTAWAY HISTORY.
# Stage 1 (data foundation): pure builders + a daily-cached accessor.
#   booking date = reservationDate (verified 100% populated, correct for
#   imported history); confirmed = status in {new, modified}; lead =
#   arrivalDate - reservationDate (drop < 0). ADR = totalPrice / nights.
# Every value is computed from real reservations or omitted — never faked.
# =====================================================================
PE_HORIZON = int(os.environ.get("PRICE_OPP_HORIZON", "45"))      # days-out we learn/price
PE_WEEKEND_DOW = {3, 4, 5}                                       # Thu,Fri,Sat (Mon=0); validated vs learned ADR-by-weekday
PE_LEAD_BUCKETS = [(0, 0, "same-day"), (1, 2, "1-2d"), (3, 5, "3-5d"),
                   (6, 10, "6-10d"), (11, 20, "11-20d"), (21, 99999, "21+d")]
# When several calendar events overlap a date, the more specific one wins the tag.
_PE_EVENT_PRIORITY = {"eid": 0, "national": 1, "ramadan": 2, "season": 3}

def _pe_lead_bucket(lead):
    for lo, hi, lbl in PE_LEAD_BUCKETS:
        if lo <= lead <= hi:
            return lbl
    return "21+d"

def _pe_group_key(u):
    """Pool key = compound (neighbourhood) + size (bedrooms) + tier (property type)."""
    nb = (u.get("neighbourhood") or u.get("area") or "").strip() or "—"
    beds = u.get("beds")
    beds = int(beds) if isinstance(beds, (int, float)) else (str(beds) if beds else "?")
    pt = (u.get("ptype") or "").strip() or "—"
    return f"{nb} · {beds}BR · {pt}"

def _pe_groups(units=None):
    """Return (lid->group_key, group_key->[lids], lid->unit-dict) from the catalog."""
    units = units if units is not None else (_catalog_units or [])
    l2g, g2l, l2u = {}, {}, {}
    for u in units:
        lid = u.get("id")
        if lid is None:
            continue
        gk = _pe_group_key(u)
        l2g[lid] = gk
        l2u[lid] = u
        g2l.setdefault(gk, []).append(lid)
    return l2g, g2l, l2u

def _pe_date_type(d):
    """(type, event_name|None). A calendar event overrides weekend/weekday.
    Uses the real SAUDI_EVENTS calendar; school-break is intentionally NOT tagged
    (no trustworthy date source) rather than guessed."""
    evs = events_for_date(d) or []
    if evs:
        evs = sorted(evs, key=lambda e: _PE_EVENT_PRIORITY.get(e.get("kind"), 9))
        e = evs[0]
        return (e.get("kind") or "event", e.get("name"))
    if d.weekday() in PE_WEEKEND_DOW:
        return ("weekend", None)
    return ("weekday", None)

def _pe_res_nights(r):
    n = r.get("nights")
    if isinstance(n, (int, float)) and n > 0:
        return int(n)
    ci, co = _parse_date(r.get("arrivalDate")), _parse_date(r.get("departureDate"))
    return (co - ci).days if (ci and co and co > ci) else 0

def _pe_build_dataset(reservations, units, today):
    """PURE. Night-level dataset of confirmed bookings, keyed off reservationDate.
    Returns nights[] (one record per booked unit-night) + counts + a learned
    ADR-by-weekday readout + group maps + the observed date range. No I/O."""
    import statistics
    l2g, g2l, l2u = _pe_groups(units)
    today_iso = today.isoformat()
    nights = []
    n_conf = n_neg = n_used = 0
    wd_adr = {i: [] for i in range(7)}
    for r in reservations:
        if (r.get("status") or "").lower() not in CONFIRMED_STATUSES:
            continue
        n_conf += 1
        ci = _parse_date(r.get("arrivalDate"))
        rd = _parse_date(r.get("reservationDate"))
        nn = _pe_res_nights(r)
        tp = r.get("totalPrice")
        if not ci or not rd or nn <= 0 or not isinstance(tp, (int, float)) or tp <= 0:
            continue
        lead = (ci - rd).days
        if lead < 0:                       # drop the ~0.2% with negative lead
            n_neg += 1
            continue
        n_used += 1
        adr = tp / nn
        lid = r.get("listingMapId")
        grp = l2g.get(lid)                 # None if unit not in the active catalog
        chan = r.get("channelName") or "?"
        for i in range(nn):
            nd = ci + timedelta(days=i)
            dt, ev = _pe_date_type(nd)
            nights.append({"lid": lid, "group": grp, "date": nd.isoformat(), "dtype": dt,
                           "event": ev, "adr": round(adr, 2), "lead": lead,
                           "bucket": _pe_lead_bucket(lead), "channel": chan,
                           "arrival": ci.isoformat()})
            wd_adr[nd.weekday()].append(adr)
    wd_median = {i: (round(statistics.median(v)) if v else None) for i, v in wd_adr.items()}
    all_dates = [n["date"] for n in nights]
    return {"nights": nights, "n_confirmed": n_conf, "n_negative_lead": n_neg, "n_used": n_used,
            "wd_median_adr": wd_median, "groups_lid": l2g, "group_units": g2l,
            "n_groups": len(g2l), "n_units": len(l2u),
            "date_min": min(all_dates) if all_dates else None,
            "date_max": max(all_dates) if all_dates else None,
            "past_max": max((d for d in all_dates if d <= today_iso), default=None)}

def _pe_reconstruct_pace(nights, group_units, horizon=PE_HORIZON):
    """PURE. Per (group, date-type) reconstruct, from booked nights' lead times:
      booking_curve[t] = share of eventual bookings already on the books t days out
                       = P(lead >= t)         (capacity-free; quantifies the curve)
      typical_occ[t]   = booked-unit-nights(lead>=t) / (units_in_group * distinct_nights)
                       (the pace baseline). final_occ = typical_occ[0].
    The distinct-nights denominator is an approximation that tightens as data grows."""
    import statistics, bisect
    from collections import defaultdict
    leads = defaultdict(list)              # (group,dtype) -> [lead per booked unit-night]
    ndset = defaultdict(set)               # (group,dtype) -> {distinct night-date}
    for n in nights:
        g = n.get("group")
        if not g:
            continue
        key = (g, n["dtype"])
        leads[key].append(n["lead"])
        ndset[key].add(n["date"])
    out = {}
    for key, lds in leads.items():
        g, dt = key
        total = len(lds)
        K = max(1, len(group_units.get(g, [])))
        N = max(1, len(ndset[key]))
        srt = sorted(lds)
        booking_curve, typical_occ = {}, {}
        for t in range(0, horizon + 1):
            ge = total - bisect.bisect_left(srt, t)       # count of leads >= t
            booking_curve[t] = round(ge / total, 4) if total else 0.0
            typical_occ[t] = round(ge / (K * N), 4)
        out[f"{g}||{dt}"] = {"group": g, "dtype": dt, "n_bookings": total, "n_nights": N,
                             "units": K, "final_occ": round(total / (K * N), 4),
                             "lead_median": int(statistics.median(lds)) if lds else None,
                             "booking_curve": booking_curve, "typical_occ": typical_occ}
    return out

PE_MIN_UNIT = int(os.environ.get("PE_MIN_UNIT", "8"))     # min bookings to trust a unit's OWN band (else pool to group)
PE_EVENT_MIN = int(os.environ.get("PE_EVENT_MIN", "10"))  # min event-nights for a high-confidence learned effect

def _pe_band(adrs):
    """Realized ADR band from a list of booked ADRs (nearest-rank percentiles)."""
    if not adrs:
        return None
    import statistics
    s = sorted(adrs)
    n = len(s)
    def pct(p):
        return round(s[min(n - 1, max(0, int(round((p / 100.0) * (n - 1)))))])
    return {"count": n, "min": round(s[0]), "max": round(s[-1]),
            "median": round(statistics.median(s)), "avg": round(sum(s) / n),
            "p10": pct(10), "p90": pct(90)}

def _pe_learn_models(data):
    """PURE. From the night-level dataset learn the transparent, explainable models:
      (3) booking-curve buckets per group x date-type (% of bookings per lead bucket),
      (4) realized ADR bands per unit and per group x date-type (and x lead bucket),
      (5) calendar effects per event: ADR uplift + pace shift LEARNED vs a same-group
          non-event baseline (thin data -> low confidence + an honest note).
    Nothing is assumed; the SAUDI_EVENTS boost is carried only as a labelled reference."""
    import statistics
    from collections import defaultdict
    nights = data["nights"]
    adr_unit_dt, adr_grp_dt = defaultdict(list), defaultdict(list)
    adr_unit_dt_bkt, adr_grp_dt_bkt = defaultdict(list), defaultdict(list)
    leads_grp_dt = defaultdict(list)
    ev_adr, ev_leads, ev_groups = defaultdict(list), defaultdict(list), defaultdict(set)
    base_adr_grp, base_leads_grp = defaultdict(list), defaultdict(list)
    all_adr = []
    for n in nights:
        a, dt, lid, g, bkt, ev = n["adr"], n["dtype"], n["lid"], n["group"], n["bucket"], n.get("event")
        all_adr.append(a)
        if lid is not None:
            adr_unit_dt[(lid, dt)].append(a)
            adr_unit_dt_bkt[(lid, dt, bkt)].append(a)
        if g:
            adr_grp_dt[(g, dt)].append(a)
            adr_grp_dt_bkt[(g, dt, bkt)].append(a)
            leads_grp_dt[(g, dt)].append(n["lead"])
            if ev:
                ev_adr[ev].append(a); ev_leads[ev].append(n["lead"]); ev_groups[ev].add(g)
            else:
                base_adr_grp[g].append(a); base_leads_grp[g].append(n["lead"])
    unit_bands = {f"{lid}||{dt}": _pe_band(v) for (lid, dt), v in adr_unit_dt.items()}
    group_bands = {f"{g}||{dt}": _pe_band(v) for (g, dt), v in adr_grp_dt.items()}
    unit_bands_bucket = {f"{lid}||{dt}||{bkt}": _pe_band(v) for (lid, dt, bkt), v in adr_unit_dt_bkt.items()}
    group_bands_bucket = {f"{g}||{dt}||{bkt}": _pe_band(v) for (g, dt, bkt), v in adr_grp_dt_bkt.items()}
    curve_buckets = {}
    for (g, dt), lds in leads_grp_dt.items():
        tot = len(lds)
        cnt = {lbl: 0 for _, _, lbl in PE_LEAD_BUCKETS}
        for L in lds:
            cnt[_pe_lead_bucket(L)] += 1
        curve_buckets[f"{g}||{dt}"] = {lbl: round(cnt[lbl] / tot, 4) for lbl in cnt} if tot else {}
    assumed = {e["name"]: e.get("boost") for e in _all_events()}
    events = {}
    for ev, adrs in ev_adr.items():
        grps = ev_groups.get(ev, set())
        base = [a for g in grps for a in base_adr_grp.get(g, [])]
        base_ld = [L for g in grps for L in base_leads_grp.get(g, [])]
        n_ev = len(adrs)
        uplift = (round(statistics.median(adrs) / statistics.median(base), 3)
                  if base and statistics.median(base) > 0 else None)
        pace_shift = (round(statistics.median(ev_leads[ev]) - statistics.median(base_ld), 1)
                      if base_ld else None)
        conf = "high" if (n_ev >= PE_EVENT_MIN and base) else "low"
        events[ev] = {"n": n_ev, "learned_uplift": uplift, "pace_shift_days": pace_shift,
                      "assumed_boost": assumed.get(ev), "confidence": conf,
                      "note": None if conf == "high" else "بيانات قليلة لهالمناسبة"}
    return {"unit_bands": unit_bands, "group_bands": group_bands,
            "unit_bands_bucket": unit_bands_bucket, "group_bands_bucket": group_bands_bucket,
            "curve_buckets": curve_buckets, "events": events,
            "overall_adr": round(statistics.median(all_adr)) if all_adr else None,
            "min_unit": PE_MIN_UNIT}

# Daily-refreshed cache for the learned dataset + pace reconstruction + models.
_pe_cache = {"data": None, "pace": None, "models": None, "ts": 0, "error": None}

def _pe_get(force=False, ttl=86400):
    """Build (or return cached) the Stage-1 dataset + pace. Cached ~24h (daily)."""
    if (not force) and _pe_cache["data"] and (time.time() - _pe_cache["ts"] < ttl):
        return _pe_cache
    try:
        if not _catalog_units:
            load_catalog(True)
        today = datetime.now(TZ).date()
        data = _pe_build_dataset(get_reservations_cached(), _catalog_units, today)
        pace = _pe_reconstruct_pace(data["nights"], data["group_units"])
        models = _pe_learn_models(data)
        _pe_backfill_outcomes(data)        # learning loop: record real booked outcomes daily
        _pe_cache.update({"data": data, "pace": pace, "models": models, "ts": time.time(), "error": None})
    except Exception as e:
        _pe_cache["error"] = str(e)
        print("pricing-engine v2 build error:", e)
    return _pe_cache

# ---- Stage 3: pace + recommendation engine (per upcoming open night, per unit) ----
_pe_floor_overrides = {}     # optional {lid: absolute SAR floor} the owner can set; default none

def _pe_resolve_band(models, lid, g, dtype, ev):
    """Pick the realized ADR band to anchor on. Prefer the unit's OWN band when rich,
    else the group's; for an event date-type with thin direct data, estimate from the
    group's base band x the learned (or assumed) event uplift. Returns (band, source)."""
    ub = models["unit_bands"].get(f"{lid}||{dtype}")
    if ub and ub.get("count", 0) >= PE_MIN_UNIT:
        return ub, "unit"
    gb = models["group_bands"].get(f"{g}||{dtype}") if g else None
    if gb and gb.get("count", 0) >= PE_MIN_UNIT:
        return gb, "group"
    if ev and g:
        base = models["group_bands"].get(f"{g}||weekend") or models["group_bands"].get(f"{g}||weekday")
        eff = models["events"].get(ev) or {}
        up = eff.get("learned_uplift") or eff.get("assumed_boost")
        if base and up:
            est = dict(base)
            for k in ("min", "max", "median", "avg", "p10", "p90"):
                if isinstance(est.get(k), (int, float)):
                    est[k] = int(round(est[k] * up))
            return est, "event-est"
    if ub:
        return ub, "unit-thin"
    if gb:
        return gb, "group"
    return None, None

def _pe_reco_for_night(d, today, dtype, ev, current_price, band, band_source,
                       ev_effect, pace_entry, occ_now_frac, manual_floor=0):
    """PURE. One night's recommendation. Far-out (>10d) holds the anchor and never
    pre-discounts (raises early only for events that historically book early); near-in
    (0-10d) moves with the pace signal toward floor (behind) or ceiling (ahead). Never
    below the hard floor. Returns a dict, or None if there is no band (omit, don't fake)."""
    if not band or not band.get("median"):
        return None
    median = band["median"]
    days_out = (d - today).days
    floor = max(int(round(0.70 * median)), int(manual_floor or 0))
    ceiling = max(int(round(min(band.get("p90") or median * 1.5, 2.0 * median))), floor)
    # pace signal: current on-the-books vs historical typical at this same days-out
    typ = pace_entry["typical_occ"].get(days_out) if (pace_entry and pace_entry.get("typical_occ")) else None
    if typ is not None and occ_now_frac is not None:
        if occ_now_frac > typ * 1.15 + 1e-9:
            signal = "ahead"
        elif occ_now_frac < typ * 0.85 - 1e-9:
            signal = "behind"
        else:
            signal = "normal"
    else:
        signal = "normal"
    early_event = bool(ev) and bool(ev_effect) and (ev_effect.get("pace_shift_days") or 0) > 5
    if days_out > 10:
        if early_event:
            rec = median + 0.60 * (ceiling - median)        # events that book early -> raise early
        elif signal == "ahead":
            rec = median + 0.40 * (ceiling - median)
        else:
            rec = median                                    # hold a confident anchor; do NOT pre-discount
    else:
        if signal == "behind":
            frac = max(0.0, min(1.0, 1.0 - days_out / 10.0))   # closer to check-in -> deeper toward floor
            rec = median - frac * (median - floor)
        elif signal == "ahead":
            rec = median + 0.50 * (ceiling - median)
        else:
            rec = median
    rec = int(round(max(floor, min(ceiling, rec))))
    out = {"date": d.isoformat(), "days_out": days_out, "dtype": dtype, "event": ev,
           "recommended": rec, "floor": floor, "ceiling": ceiling, "median": median,
           "signal": signal, "band_source": band_source, "band_count": band.get("count"),
           "occ_now": (round(occ_now_frac, 3) if occ_now_frac is not None else None),
           "typical_occ": (round(typ, 3) if typ is not None else None),
           "confidence": "high" if band_source == "unit" else "low"}
    if isinstance(current_price, (int, float)) and current_price > 0:
        out["current"] = int(round(current_price))
        out["delta"] = out["recommended"] - out["current"]
        out["delta_pct"] = round(100.0 * out["delta"] / out["current"], 1)
        out["opportunity"] = abs(out["delta"])
    else:
        out["current"] = None
        out["delta"] = None
        out["opportunity"] = 0
    return out

def _pe_fetch_calendars(lids, today, horizon):
    """Fetch each unit's forward calendar [today, today+horizon] in parallel (GET only)."""
    start, end = today.isoformat(), (today + timedelta(days=horizon)).isoformat()
    out = {}
    def fetch(lid):
        try:
            cal = api_get(f"/listings/{lid}/calendar", params={"startDate": start, "endDate": end})
            days = {}
            for day in (cal.get("result") or []):
                ds = day.get("date")
                if not ds:
                    continue
                avail = int(day.get("isAvailable", 0) or 0) == 1
                days[ds] = {"avail": avail, "booked": (not avail) or bool(day.get("reservationId")),
                            "price": day.get("price")}
            return lid, days
        except Exception as e:
            print(f"pe calendar {lid}:", e)
            return lid, {}
    if not lids:
        return out
    try:
        with ThreadPoolExecutor(max_workers=INTEL_PARALLEL) as ex:
            for f in as_completed([ex.submit(fetch, l) for l in lids]):
                lid, days = f.result()
                out[lid] = days
    except Exception as e:
        print("pe calendars pool error:", e)
    return out

def _pe_compute_recommendations(horizon=None):
    """Build per-(unit, open night) recommendations from the learned models + live calendars."""
    from collections import defaultdict
    c = _pe_get()
    if c.get("error") or not c.get("data") or not c.get("models"):
        return {"recs": [], "error": c.get("error") or "no data yet", "built": time.time(), "n": 0}
    data, models, pace = c["data"], c["models"], c["pace"]
    l2g = data["groups_lid"]
    today = datetime.now(TZ).date()
    horizon = horizon or PE_HORIZON
    per_unit = _pe_fetch_calendars(list(l2g.keys()), today, horizon)
    occ_book, occ_tot = defaultdict(int), defaultdict(int)
    for lid, days in per_unit.items():
        g = l2g.get(lid)
        if not g:
            continue
        for ds, row in days.items():
            occ_tot[(g, ds)] += 1
            if row["booked"]:
                occ_book[(g, ds)] += 1
    units_by_lid = {u["id"]: u for u in (_catalog_units or []) if u.get("id") is not None}
    recs = []
    for lid, days in per_unit.items():
        g = l2g.get(lid)
        uname = (units_by_lid.get(lid) or {}).get("name") or str(lid)
        for ds, row in days.items():
            d = _parse_date(ds)
            if not d or d < today or row["booked"]:
                continue                                   # only future OPEN nights are repriceable
            dtype, ev = _pe_date_type(d)
            band, source = _pe_resolve_band(models, lid, g, dtype, ev)
            if not band:
                continue                                   # no real data -> omit (never fabricate)
            tot = occ_tot.get((g, ds), 0)
            occf = (occ_book.get((g, ds), 0) / tot) if tot else None
            r = _pe_reco_for_night(d, today, dtype, ev, row.get("price"), band, source,
                                   models["events"].get(ev) if ev else None,
                                   pace.get(f"{g}||{dtype}"), occf,
                                   _pe_floor_overrides.get(lid, 0))
            if not r:
                continue
            r.update({"lid": lid, "unit": uname, "group": g})
            recs.append(r)
    recs.sort(key=lambda r: -(r.get("opportunity") or 0))
    return {"recs": recs, "n": len(recs), "built": time.time(), "horizon": horizon,
            "n_units": len(per_unit), "footer_n": data.get("n_used", 0),
            "wd_median_adr": data.get("wd_median_adr")}

_pe_rec_cache = {"data": None, "ts": 0}

def _pe_get_recs(force=False, ttl=900):
    """Cached recommendation list (~15 min). Decorated live on every read with the final price +
    active strategy layers/badges so toggles + active strategies reflect immediately."""
    if (not force) and _pe_rec_cache["data"] and (time.time() - _pe_rec_cache["ts"] < ttl):
        return _pe_decorate(_pe_rec_cache["data"])
    _pe_rec_cache.update({"data": _pe_compute_recommendations(), "ts": time.time()})
    return _pe_decorate(_pe_rec_cache["data"])

# ---- Stage 6 (learning loop): persist applies; backfill real outcomes daily; summarize ----
# (Future: gentle A/B price-testing for true elasticity — FLAGGED, not built. Observational
#  data gives strong heuristics, not guaranteed elasticity; this loop sharpens them over time.)
PE_PRICE_TESTING_ENABLED = False   # intentionally off — do not auto-experiment on live prices
_pe_reco_log = []   # [{ts, lid, date, price, applied, dry, confirmed, booked, booked_at, booked_price}]

def _pe_log_save():
    try:
        _save_json("pe_reco_log", _pe_reco_log[-5000:])
    except Exception as e:
        print("pe log save:", e)

def _pe_log_reco(lid, date_iso, price, applied=False, dry=False, confirmed=None):
    try:
        _pe_reco_log.append({"ts": datetime.now(TZ).isoformat(timespec="seconds"), "lid": lid,
                             "date": date_iso, "price": int(price), "applied": bool(applied),
                             "dry": bool(dry), "confirmed": confirmed,
                             "booked": None, "booked_at": None, "booked_price": None})
        if len(_pe_reco_log) > 5000:
            del _pe_reco_log[:len(_pe_reco_log) - 5000]
        _pe_log_save()
    except Exception as e:
        print("pe log error:", e)

try:
    _pe_loaded = _load_json("pe_reco_log", [])
    if isinstance(_pe_loaded, list):
        _pe_reco_log.extend(_pe_loaded)
except Exception:
    pass

# ====================================================================
#  CENTRAL PRICE-CHANGE AUDIT LOG (the trust mechanism)
#  EVERY price write — engine, strategy rule, same-day step-down, manual edit,
#  per-month apply, the daily job — routes through log_price_change(), which
#  appends to a per-(listing, date) APPEND-ONLY timeline: timestamp, old→new,
#  source, reason. Entries are never edited or deleted.
# ====================================================================
PRICE_LOG_FILE = "price_change_log.json"
_price_log = {}                    # "<lid>|<YYYY-MM-DD>" -> [ {ts, old, new, source, reason, dry, confirmed} ]
_PRICE_LOG_MAX_PER_KEY = 80        # keep the most recent N entries per date (append-only within that window)
_price_log_lock = threading.Lock()

try:
    _pl_loaded = _load_json(PRICE_LOG_FILE, {})
    if isinstance(_pl_loaded, dict):
        _price_log.update(_pl_loaded)
except Exception:
    pass

# Human labels for each price-change source (shown in the per-date timeline).
PRICE_SOURCE_LABEL = {
    "manual":      {"ar": "تعديل يدوي", "en": "manual edit", "icon": "✋"},
    "engine":      {"ar": "محرّك التسعير", "en": "pricing engine", "icon": "🧠"},
    "strategy":    {"ar": "استراتيجية ديناميكية", "en": "dynamic strategy", "icon": "⚡"},
    "last-minute": {"ar": "خصم اللحظة الأخيرة", "en": "last-minute step-down", "icon": "⏱️"},
    "monthly":     {"ar": "تطبيق شهري", "en": "monthly apply", "icon": "📅"},
    "bulk":        {"ar": "تطبيق جماعي", "en": "bulk apply", "icon": "📦"},
    "daily-job":   {"ar": "المهمة اليومية", "en": "daily job", "icon": "🔁"},
}

def _price_log_save():
    try:
        _save_json(PRICE_LOG_FILE, _price_log)
    except Exception as e:
        print("price log save:", e)

def _coerce_price(v):
    if v in (None, "", "null"):
        return None
    try:
        return int(round(float(v)))
    except (TypeError, ValueError):
        return None

def log_price_change(lid, date_iso, old_price, new_price, source, reason="", dry=False, confirmed=None):
    """Append ONE entry to the per-(listing, date) append-only audit trail. Called by EVERY
    price-writing path so each date carries a complete, trustworthy timeline. Never edits or
    deletes. Returns the entry (or None if the inputs were unusable)."""
    try:
        key = f"{int(lid)}|{str(date_iso)[:10]}"
    except (TypeError, ValueError):
        return None
    entry = {"ts": datetime.now(TZ).isoformat(timespec="seconds"),
             "old": _coerce_price(old_price), "new": _coerce_price(new_price),
             "source": source, "reason": reason or "",
             "dry": bool(dry), "confirmed": confirmed}
    with _price_log_lock:
        lst = _price_log.setdefault(key, [])
        lst.append(entry)
        if len(lst) > _PRICE_LOG_MAX_PER_KEY:
            del lst[:len(lst) - _PRICE_LOG_MAX_PER_KEY]
        _price_log_save()
    return entry

def price_change_log(lid, date_iso):
    """The full timeline for one (listing, date), oldest first (a shallow copy)."""
    try:
        return list(_price_log.get(f"{int(lid)}|{str(date_iso)[:10]}", []))
    except (TypeError, ValueError):
        return []

# ====================================================================
#  STRATEGY TOGGLES + FINAL-PRICE LAYER MODEL  (Stage 3 + Stage 7)
#  All strategies are ON by default. They can be disabled globally and/or per
#  unit. The "final price" model is transparent:
#     engine base recommendation  →  active strategy layers  →  final price.
#  weekend/event are informational layers (already inside the learned base);
#  last-minute step-down and the dynamic strategy are REAL layers that move the
#  number, and disabling either removes its effect.
# ====================================================================
STRATEGY_TOGGLE_FILE = "strategy_toggles.json"
STRATEGY_KEYS = ["last-minute", "strategy", "weekend", "event"]
STRATEGY_KEY_LABEL = {
    "last-minute": {"ar": "خصم اللحظة الأخيرة", "en": "Last-minute step-down", "icon": "⏱️", "real": True},
    "strategy":    {"ar": "الاستراتيجية الديناميكية", "en": "Dynamic strategy", "icon": "⚡", "real": True},
    "weekend":     {"ar": "تسعير نهاية الأسبوع", "en": "Weekend pricing", "icon": "📆", "real": False},
    "event":       {"ar": "تسعير المناسبات", "en": "Event pricing", "icon": "🎉", "real": False},
}
_strategy_toggles = {"global": {}, "by_unit": {}}    # absence = ENABLED (ON by default)
try:
    _st_loaded = _load_json(STRATEGY_TOGGLE_FILE, None)
    if isinstance(_st_loaded, dict):
        _strategy_toggles["global"] = _st_loaded.get("global", {}) or {}
        _strategy_toggles["by_unit"] = _st_loaded.get("by_unit", {}) or {}
except Exception:
    pass

def _strategy_toggles_save():
    try:
        _save_json(STRATEGY_TOGGLE_FILE, _strategy_toggles)
    except Exception as e:
        print("strategy toggle save:", e)

def strategy_enabled(name, lid=None):
    """True unless the strategy is disabled globally OR for this specific unit (ON by default)."""
    if _strategy_toggles["global"].get(name) is False:
        return False
    if lid is not None:
        u = _strategy_toggles["by_unit"].get(str(lid))
        if isinstance(u, dict) and u.get(name) is False:
            return False
    return True

def set_strategy_toggle(name, enabled, lid=None):
    """Enable/disable a strategy globally (lid=None) or for one unit. Returns False on bad name."""
    if name not in STRATEGY_KEYS:
        return False
    if lid is None:
        if enabled:
            _strategy_toggles["global"].pop(name, None)
        else:
            _strategy_toggles["global"][name] = False
    else:
        u = _strategy_toggles["by_unit"].setdefault(str(lid), {})
        if enabled:
            u.pop(name, None)
        else:
            u[name] = False
        if not u:
            _strategy_toggles["by_unit"].pop(str(lid), None)
    _strategy_toggles_save()
    return True

def _event_names_for(d):
    out = []
    for e in (events_for_date(d) if d else []):
        nm = e.get("name") or e.get("label") or e.get("id")
        if nm:
            out.append(nm)
    return out

def _active_layers_for(lid, date_iso, base_price, current_price):
    """Active strategy layers on (lid, date) + the resulting FINAL price (honors toggles).
    base = engine recommendation; final = the dynamic-strategy target when a strategy manages
    the date (else base). weekend/event are informational (already inside the learned base).
    Returns {final, base, source, color, layers:[{key,label_ar,label_en,icon,enabled,real,note_ar,effect}]}."""
    d = _parse_date(date_iso)
    today = datetime.now(TZ).date()
    base_price = base_price or current_price
    final = base_price
    source = "engine"
    layers = []
    def _add(key, note_ar="", effect=None):
        meta = STRATEGY_KEY_LABEL[key]
        layers.append({"key": key, "label_ar": meta["ar"], "label_en": meta["en"],
                       "icon": meta["icon"], "real": meta["real"],
                       "enabled": strategy_enabled(key, lid), "note_ar": note_ar, "effect": effect})
    if d and d.weekday() in WEEKEND_DAYS:
        _add("weekend", "السعر المتعلّم يشمل تأثير نهاية الأسبوع أصلاً")
    evs = _event_names_for(d)
    if evs:
        _add("event", "·".join(evs), effect="·".join(evs))
    strat = _pricing_strategies.get(lid)
    if strat and strat.get("active") and date_iso in (strat.get("dates") or {}):
        _add("strategy", "البوت يتابع هالليلة ويعيد تحسينها تلقائياً")
        if strategy_enabled("strategy", lid):
            tgt = (strat["dates"].get(date_iso) or {}).get("cur")
            if tgt:
                final = int(round(tgt))
                source = "strategy"
    if d == today:
        _add("last-minute", "ينزل السعر تدريجياً اليوم لو ظلّت فاضية (حتى ~-٣٠٪)")
    color = "hold"
    if current_price and final:
        if final > current_price + 0.5:
            color = "raise"
        elif final < current_price - 0.5:
            color = "drop"
    return {"final": (int(round(final)) if final else None), "base": base_price,
            "source": source, "color": color, "layers": layers}

def _pe_decorate(data):
    """Attach the final price + active strategy layers/badges to every cached rec (live —
    reflects current toggles + active strategies on each read)."""
    for r in (data.get("recs") or []):
        info = _active_layers_for(r.get("lid"), r.get("date"), r.get("recommended"), r.get("current"))
        r["final"] = info["final"]
        r["final_color"] = info["color"]
        r["final_source"] = info["source"]
        r["layers"] = info["layers"]
        r["badges"] = [L["key"] for L in info["layers"] if L["enabled"]]
    return data

def _pe_backfill_outcomes(data):
    """For logged actions whose night has since booked (now appears among confirmed
    reservations), record booked_at = the real reservationDate and booked_price = realized
    ADR. Real outcomes only — never inferred. Runs on the daily rebuild."""
    try:
        idx = {}
        for n in data.get("nights", []):
            key = (n["lid"], n["date"])
            if key not in idx:
                ci = _parse_date(n["arrival"])
                idx[key] = {"booked_at": (ci - timedelta(days=n["lead"])).isoformat() if ci else None,
                            "price": round(n["adr"])}
        changed = False
        for e in _pe_reco_log:
            if e.get("booked") is None:
                info = idx.get((e.get("lid"), e.get("date")))
                if info:
                    e["booked"], e["booked_at"], e["booked_price"] = True, info["booked_at"], info["price"]
                    changed = True
        if changed:
            _pe_log_save()
    except Exception as ex:
        print("pe backfill:", ex)

def _pe_learning_summary():
    """Feedback signal from real outcomes: how applied recommendations actually fared."""
    applied = [e for e in _pe_reco_log if e.get("applied") and not e.get("dry")]
    booked = [e for e in applied if e.get("booked")]
    out = {"logged_total": len(_pe_reco_log), "applied_real": len(applied), "applied_then_booked": len(booked)}
    diffs = [e["booked_price"] - e["price"] for e in booked if e.get("booked_price") and e.get("price")]
    if diffs:
        out["avg_booked_minus_applied"] = round(sum(diffs) / len(diffs))
    return out

# ---- Stage 4: the "ليش هالسعر؟" explainability payload (every value real, or the row is omitted) ----
_PE_DTYPE_AR = {"weekday": "يوم عادي (وسط الأسبوع)", "weekend": "نهاية الأسبوع (خميس–سبت)"}

def _pe_demand_pill(signal):
    return {"ahead": "الطلب مرتفع", "behind": "الطلب منخفض"}.get(signal, "الطلب عادي")

def _pe_night_detail(lid, date_iso):
    """Full panel payload for one (unit, night): the reco + a factor breakdown where every
    sentence carries a REAL computed number, and any factor without data is omitted."""
    c = _pe_get()
    if c.get("error") or not c.get("data") or not c.get("models"):
        return {"error": c.get("error") or "no data yet"}
    data, models, pace = c["data"], c["models"], c["pace"]
    g = data["groups_lid"].get(lid)
    d = _parse_date(date_iso)
    if not d:
        return {"error": "bad date"}
    today = datetime.now(TZ).date()
    dtype, ev = _pe_date_type(d)
    band, source = _pe_resolve_band(models, lid, g, dtype, ev)
    if not band:
        return {"error": "no realized data for this unit/day-type"}
    units_by_lid = {u["id"]: u for u in (_catalog_units or []) if u.get("id") is not None}
    uname = (units_by_lid.get(lid) or {}).get("name") or str(lid)
    # prefer the cached rec (has live current price + group pace); else compute without occ
    # A1: ALWAYS read the LIVE per-night Hostaway calendar price so the panel's current is
    # never stale (the list is cached; the detail you act on must be real-time).
    live_cur = None
    try:
        cal = api_get(f"/listings/{lid}/calendar", params={"startDate": date_iso, "endDate": date_iso})
        for day in (cal.get("result") or []):
            if day.get("date") == date_iso:
                live_cur = day.get("price")
    except Exception as e:
        print("pe night live-price error:", e)
    rec = None
    for r in (_pe_get_recs().get("recs") or []):
        if r.get("lid") == lid and r.get("date") == date_iso:
            rec = dict(r)
            break
    if rec is None:
        rec = _pe_reco_for_night(d, today, dtype, ev, live_cur, band, source,
                                 models["events"].get(ev) if ev else None,
                                 pace.get(f"{g}||{dtype}"), None, _pe_floor_overrides.get(lid, 0))
        if rec:
            rec.update({"lid": lid, "unit": uname, "group": g})
    elif live_cur is not None and live_cur > 0:        # refresh the cached rec's current to live
        rec["current"] = int(round(live_cur))
        rec["delta"] = rec["recommended"] - rec["current"]
        rec["delta_pct"] = round(100.0 * rec["delta"] / rec["current"], 1)
    if not rec:
        return {"error": "could not compute"}
    pe = pace.get(f"{g}||{dtype}") or {}
    pooled = source in ("group", "event-est", "unit-thin")
    factors = []
    # 1) day-type
    dt_label = ev or _PE_DTYPE_AR.get(dtype, dtype)
    factors.append({"icon": "📅", "key": "نوع اليوم",
                    "text": f"{dt_label} — متوسط سعرك المحقّق لهالنوع {band['median']:,} ر.س",
                    "effect": dt_label})
    # 2) your realized prices
    src_tail = "" if source == "unit" else " (من وحدات مشابهة)"
    factors.append({"icon": "💰", "key": "أسعار حجوزاتك الفعلية",
                    "text": f"آخر {band['count']} حجز لنفس النوع — المتوسط {band['avg']:,}، الأعلى {band['max']:,} ر.س{src_tail}",
                    "effect": f"{band['count']} حجز"})
    # 3) booking pace (only if we have live occupancy)
    if rec.get("occ_now") is not None and rec.get("typical_occ") is not None:
        pace_word = {"ahead": "أسرع", "behind": "أبطأ"}.get(rec["signal"], "مثل")
        factors.append({"icon": "⏱️", "key": "سرعة الحجز",
                        "text": f"محجوزة {round(rec['occ_now']*100)}٪ وباقي {rec['days_out']} يوم — {pace_word} من المعتاد ({round(rec['typical_occ']*100)}٪)",
                        "effect": _pe_demand_pill(rec["signal"])})
    # 4) your booking habit (median lead)
    if pe.get("lead_median") is not None:
        factors.append({"icon": "📈", "key": "عادة الحجز عندك",
                        "text": f"عادةً هالنوع ينحجز قبل ~{pe['lead_median']} يوم من الوصول",
                        "effect": f"~{pe['lead_median']} يوم"})
    # 5) event (only if a real event applies)
    if ev:
        eff = models["events"].get(ev) or {}
        up = eff.get("learned_uplift")
        if up:
            pct = round((up - 1) * 100)
            factors.append({"icon": "🎉", "key": "مناسبة",
                            "text": f"{ev}: حجوزاتك بهالمناسبة بمتوسط {'+' if pct>=0 else ''}{pct}٪ عن العادي"
                                    + ("" if eff.get("confidence") == "high" else " — بيانات قليلة لهالمناسبة"),
                            "effect": ev})
        elif eff.get("assumed_boost"):
            factors.append({"icon": "🎉", "key": "مناسبة",
                            "text": f"{ev}: تقدير من تقويم المناسبات (+{round((eff['assumed_boost']-1)*100)}٪) — ما عندنا حجوزات كافية بعد",
                            "effect": ev})
    # 6) hard floor
    factors.append({"icon": "🛡️", "key": "الحد الأدنى للوحدة",
                    "text": f"ما ننزل تحت {rec['floor']:,} ر.س لهالوحدة", "effect": f"{rec['floor']:,} ر.س"})
    # 7) confidence
    if rec["confidence"] == "high":
        factors.append({"icon": "✅", "key": "مستوى الثقة", "text": "ثقة عالية — بيانات كافية لهالوحدة بالذات", "effect": "عالية"})
    else:
        factors.append({"icon": "⚠️", "key": "مستوى الثقة",
                        "text": "ثقة منخفضة — بيانات قليلة لهالوحدة، فنستأنس بوحدات مشابهة", "effect": "منخفضة"})
    # summary line
    sig_phrase = {"ahead": "والحجز أسرع من المعتاد", "behind": "والحجز أبطأ من المعتاد"}.get(rec["signal"], "")
    summary = f"{dt_label}، وحجوزاتك الفعلية متوسطها {band['median']:,} ر.س {sig_phrase}. نقترح {rec['recommended']:,} ر.س ضمن [{rec['floor']:,}–{rec['ceiling']:,}]."
    info = _active_layers_for(lid, date_iso, rec["recommended"], rec.get("current"))
    return {"lid": lid, "unit": uname, "date": date_iso, "days_out": rec["days_out"],
            "dtype": dtype, "event": ev, "demand_pill": _pe_demand_pill(rec["signal"]),
            "signal": rec["signal"], "current": rec.get("current"), "recommended": rec["recommended"],
            "delta": rec.get("delta"), "delta_pct": rec.get("delta_pct"),
            "floor": rec["floor"], "ceiling": rec["ceiling"], "median": rec["median"],
            "confidence": rec["confidence"], "pooled": pooled, "factors": factors,
            "summary": summary, "footer_n": data.get("n_used", 0),
            "dry_run": PRICE_APPLY_DRYRUN,
            # Stage 3-4: transparent final-price model + active strategies + the change log
            "final": info["final"], "final_color": info["color"], "final_source": info["source"],
            "layers": info["layers"], "changelog": _price_log_view(lid, date_iso)}

def _pe_apply_night(lid, date_iso, price, source="manual", reason="", old=None):
    """Write ONE night's price to Hostaway (one-time; honors PRICE_APPLY_DRYRUN). Returns the
    REAL result — read back to confirm — never a faked success. Logs to BOTH the learning log
    and the central price-change audit log (old→new · source · reason)."""
    try:
        price = int(round(float(price)))
    except Exception:
        return {"ok": False, "error": "bad price"}
    if price <= 0:
        return {"ok": False, "error": "bad price"}
    floor = _pe_floor_overrides.get(lid, 0)
    if floor and price < int(floor):
        return {"ok": False, "error": f"below hard floor {floor}"}
    if PRICE_APPLY_DRYRUN:
        _pe_log_reco(lid, date_iso, price, applied=True, dry=True)
        log_price_change(lid, date_iso, old, price, source, reason or "تطبيق سعر", dry=True)
        return {"ok": True, "dry_run": True, "lid": lid, "date": date_iso, "price": price,
                "note": "DRY-RUN — ما تغيّر شي فعلي"}
    try:
        if old is None:        # capture the live price BEFORE writing, for an accurate old→new
            try:
                pre = api_get(f"/listings/{lid}/calendar", params={"startDate": date_iso, "endDate": date_iso})
                for day in (pre.get("result") or []):
                    if day.get("date") == date_iso:
                        old = day.get("price")
            except Exception:
                old = None
        resp = api_put(f"/listings/{lid}/calendar",
                       {"startDate": date_iso, "endDate": date_iso, "isAvailable": 1, "price": price})
        actual = None
        chk = api_get(f"/listings/{lid}/calendar", params={"startDate": date_iso, "endDate": date_iso})
        for day in (chk.get("result") or []):
            if day.get("date") == date_iso:
                actual = day.get("price")
        confirmed = (actual is not None and abs(float(actual) - price) < 1)
        _pe_log_reco(lid, date_iso, price, applied=True, dry=False, confirmed=confirmed)
        log_price_change(lid, date_iso, old, price, source, reason or "تطبيق سعر", dry=False, confirmed=confirmed)
        return {"ok": True, "dry_run": False, "lid": lid, "date": date_iso, "price": price,
                "confirmed": confirmed, "actual": actual, "status": (resp or {}).get("status")}
    except Exception as e:
        return {"ok": False, "error": str(e), "lid": lid, "date": date_iso, "price": price}

async def _api_pe_recs(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    return _json(await asyncio.to_thread(_pe_get_recs))

async def _api_pe_night(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    try:
        lid = int(request.query.get("lid"))
    except Exception:
        return _json({"error": "bad lid"}, 400)
    date_iso = (request.query.get("date") or "")[:10]
    if not _parse_date(date_iso):
        return _json({"error": "bad date"}, 400)
    return _json(await asyncio.to_thread(_pe_night_detail, lid, date_iso))

async def _api_pe_apply(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    try:
        lid = int(b.get("lid"))
    except Exception:
        return _json({"error": "bad lid"}, 400)
    date_iso = (b.get("date") or "")[:10]
    if not _parse_date(date_iso):
        return _json({"error": "bad date"}, 400)
    res = await asyncio.to_thread(_pe_apply_night, lid, date_iso, b.get("price"),
                                  b.get("source", "manual"), b.get("reason", ""), b.get("old"))
    return _json(res)

def _price_log_view(lid, date_iso):
    """The per-date timeline shaped for the UI: each entry gets its source label + icon."""
    out = []
    for e in price_change_log(lid, date_iso):
        meta = PRICE_SOURCE_LABEL.get(e.get("source"), {"ar": e.get("source", ""), "en": e.get("source", ""), "icon": "•"})
        out.append({"ts": e.get("ts"), "old": e.get("old"), "new": e.get("new"),
                    "source": e.get("source"), "source_ar": meta["ar"], "source_en": meta["en"],
                    "icon": meta["icon"], "reason": e.get("reason", ""),
                    "dry": e.get("dry"), "confirmed": e.get("confirmed")})
    return out

async def _api_pricing_changelog(request):
    """The append-only price-change timeline for one (listing, date)."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    try:
        lid = int(request.query.get("lid"))
    except Exception:
        return _json({"error": "bad lid"}, 400)
    date_iso = (request.query.get("date") or "")[:10]
    if not _parse_date(date_iso):
        return _json({"error": "bad date"}, 400)
    return _json({"lid": lid, "date": date_iso, "log": _price_log_view(lid, date_iso)})

# ---- Stage 7: strategy on/off toggles (global + per unit) ----
async def _api_strategy_toggles(request):
    """Current on/off state of every strategy (global, and for one unit if ?lid= given)."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    try:
        lid = int(request.query.get("lid")) if request.query.get("lid") else None
    except Exception:
        lid = None
    out = []
    for k in STRATEGY_KEYS:
        meta = STRATEGY_KEY_LABEL[k]
        out.append({"key": k, "label_ar": meta["ar"], "label_en": meta["en"],
                    "icon": meta["icon"], "real": meta["real"],
                    "global_enabled": strategy_enabled(k, None),
                    "unit_enabled": (strategy_enabled(k, lid) if lid is not None else None)})
    return _json({"strategies": out, "lid": lid})

async def _api_strategy_toggle_set(request):
    """POST {name, enabled, lid?} — enable/disable a strategy globally (no lid) or per unit."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    name = b.get("name")
    if name not in STRATEGY_KEYS:
        return _json({"error": "bad strategy"}, 400)
    lid = None
    if b.get("lid") not in (None, "", 0):
        try:
            lid = int(b.get("lid"))
        except Exception:
            return _json({"error": "bad lid"}, 400)
    enabled = bool(b.get("enabled"))
    set_strategy_toggle(name, enabled, lid)
    scope = "كل الوحدات" if lid is None else f"وحدة {lid}"
    log_event("pricing", f"استراتيجية «{STRATEGY_KEY_LABEL[name]['ar']}» {'تشغيل ✅' if enabled else 'إيقاف ⏸'} · {scope}")
    return _json({"ok": True, "name": name, "lid": lid, "enabled": enabled})

# ---- Stage 6: per-month apply (preview -> confirm -> apply -> real result) ----
def _month_apply_plan(month_str):
    """Every (unit, date) in `month_str` (YYYY-MM) whose FINAL price differs from the current
    Hostaway price — the exact set the 'Apply [month]' button would write. Preview = plan."""
    recs = _pe_get_recs().get("recs") or []
    plan = []
    for r in recs:
        d = r.get("date") or ""
        if not d.startswith(month_str):
            continue
        final = r.get("final")
        cur = r.get("current")
        if final is None:
            continue
        if cur is not None and int(final) == int(cur):
            continue                                   # already at the final price — skip
        plan.append({"lid": r["lid"], "unit": r.get("unit"), "date": d,
                     "current": cur, "final": int(final), "color": r.get("final_color"),
                     "source": r.get("final_source", "engine")})
    plan.sort(key=lambda x: ((x["unit"] or ""), x["date"]))
    return plan

async def _api_pricing_month_preview(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    month = (request.query.get("month") or "")[:7]
    if not re.match(r"^\d{4}-\d{2}$", month):
        return _json({"error": "bad month"}, 400)
    plan = await asyncio.to_thread(_month_apply_plan, month)
    raises = sum(1 for p in plan if p["current"] is not None and p["final"] > p["current"])
    drops = sum(1 for p in plan if p["current"] is not None and p["final"] < p["current"])
    return _json({"month": month, "plan": plan, "count": len(plan),
                  "raises": raises, "drops": drops, "dry_run": PRICE_APPLY_DRYRUN})

async def _api_pricing_apply_month(request):
    """Apply every planned price for the month — each through _pe_apply_night (logged via the
    central audit log, DRYRUN-honoring), returning the REAL per-date result. Never faked."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    month = (b.get("month") or "")[:7]
    if not re.match(r"^\d{4}-\d{2}$", month):
        return _json({"error": "bad month"}, 400)
    plan = await asyncio.to_thread(_month_apply_plan, month)
    results = []
    for p in plan:
        res = await asyncio.to_thread(_pe_apply_night, p["lid"], p["date"], p["final"],
                                      "monthly", f"تطبيق شهري {month}", p["current"])
        results.append({"lid": p["lid"], "unit": p["unit"], "date": p["date"],
                        "final": p["final"], "current": p["current"], "ok": res.get("ok"),
                        "dry": res.get("dry_run"), "confirmed": res.get("confirmed"),
                        "error": res.get("error")})
    applied = sum(1 for r in results if r["ok"])
    failed = sum(1 for r in results if not r["ok"])
    log_event("pricing", f"تطبيق شهري {month} · {applied} نجح · {failed} فشل"
                         + (" · تجربة" if PRICE_APPLY_DRYRUN else ""))
    return _json({"month": month, "results": results, "applied": applied,
                  "failed": failed, "dry_run": PRICE_APPLY_DRYRUN})

# ---- Stage 7: backtest — prove the learned models aren't random ----
def _pe_backtest(holdout_days=90):
    """Train on bookings for arrivals BEFORE a cutoff; test on the held-out recent arrivals.
    Sanity metric: does the engine's anchor (date-type ADR band learned from TRAIN only) track
    realized ADR on the held-out nights better than chance? Reports correlation, a top-vs-bottom
    tercile actual-ADR check, and per-date-type predicted-vs-actual medians."""
    import statistics
    res = get_reservations_cached()
    if not _catalog_units:
        load_catalog(True)
    today = datetime.now(TZ).date()
    cutoff = today - timedelta(days=holdout_days)
    def arr(r):
        return _parse_date(r.get("arrivalDate"))
    train_res = [r for r in res if arr(r) and arr(r) < cutoff]
    test_res = [r for r in res if arr(r) and cutoff <= arr(r) <= today]
    train = _pe_build_dataset(train_res, _catalog_units, cutoff)
    models = _pe_learn_models(train)
    test = _pe_build_dataset(test_res, _catalog_units, today)
    pairs, by_dt = [], {}
    for n in test["nights"]:
        band, _src = _pe_resolve_band(models, n["lid"], n["group"], n["dtype"], n.get("event"))
        if not band:
            continue
        pairs.append((band["median"], n["adr"]))
        g = by_dt.setdefault(n["dtype"], {"pred": [], "act": []})
        g["pred"].append(band["median"]); g["act"].append(n["adr"])
    if len(pairs) < 30:
        return {"error": "insufficient held-out data", "n_test_pairs": len(pairs),
                "train_nights": len(train["nights"]), "test_nights": len(test["nights"])}
    npr = len(pairs)
    pred = [p for p, _ in pairs]
    act = [a for _, a in pairs]
    mp, ma = sum(pred) / npr, sum(act) / npr
    cov = sum((p - mp) * (a - ma) for p, a in pairs)
    vp = sum((p - mp) ** 2 for p in pred)
    va = sum((a - ma) ** 2 for a in act)
    r = cov / ((vp * va) ** 0.5) if vp > 0 and va > 0 else None
    srt = sorted(pairs, key=lambda x: x[0])
    k = max(1, npr // 3)
    bot_a = statistics.mean(a for _, a in srt[:k])
    top_a = statistics.mean(a for _, a in srt[-k:])
    dt_table = {dt: {"pred_median": round(statistics.median(v["pred"])),
                     "act_median": round(statistics.median(v["act"])), "n": len(v["act"])}
                for dt, v in by_dt.items()}
    return {"cutoff": cutoff.isoformat(), "train_nights": len(train["nights"]),
            "test_nights": len(test["nights"]), "n_test_pairs": npr,
            "pearson_r": round(r, 3) if r is not None else None,
            "top_tercile_actual_adr": round(top_a), "bottom_tercile_actual_adr": round(bot_a),
            "ranks_better_than_chance": bool(r and r > 0.15 and top_a > bot_a),
            "by_date_type": dt_table}

def _compute_pricing():
    reservations = get_reservations_cached()
    if not _catalog_units:
        load_catalog(True)
    factors = compute_demand_factors(reservations)
    per_unit, _ = compute_price_opportunities(factors, _catalog_units)
    _last_price_changes.clear()
    _last_price_detail.clear()
    _WD_AR = ["الاثنين", "الثلاثاء", "الأربعاء", "الخميس", "الجمعة", "السبت", "الأحد"]
    _WD_EN = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"]
    units = []
    for lid, p in sorted(per_unit.items(), key=lambda kv: kv[1]["uplift"], reverse=True):
        if not p["raise"] and not p["drop"]:
            continue
        _last_price_changes[lid] = _unit_changes(p)
        drows = []
        for r, kind in [(x, "raise") for x in p["raise"]] + [(x, "drop") for x in p["drop"]]:
            d = _parse_date(r["date"])
            mi = round(factors["month_index"].get(d.month, 1), 2) if d else 1
            di = round(factors["dom_index"].get(d.day, 1), 2) if d else 1
            wi = round(factors["dow_index"].get(d.weekday(), 1), 2) if d else 1
            drows.append({"date": r["date"], "wd_ar": _WD_AR[r["wd"]], "wd_en": _WD_EN[r["wd"]],
                          "current": r["current"], "proposed": (r["target"] if kind == "raise" else r["clear"]),
                          "kind": kind, "lead": r["lead"], "mi": mi, "di": di, "wi": wi})
        drows.sort(key=lambda x: x["date"])
        _last_price_detail[lid] = {"name": p["name"], "base": p.get("base", 0),
                                   "confidence": p.get("confidence", 50), "rows": drows}
        units.append({"lid": lid, "name": p["name"], "raise": len(p["raise"]), "drop": len(p["drop"]),
                      "uplift": round(p["uplift"]), "confidence": p.get("confidence", 50),
                      "base": p.get("base", 0)})
    return {"total_uplift": round(sum(p["uplift"] for p in per_unit.values())), "units": units[:40]}

