async def _api_reviews_translate(request):
    """POST {id, target:'en'|'ar'} → translate the review text and cache."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    rid = str(b.get("id") or "").strip()
    target = (b.get("target") or "en").strip()
    force = bool(b.get("force"))
    if not rid or rid not in _reviews:
        return _json({"error": "review not found"}, 404)
    if target not in ("en", "ar"):
        return _json({"error": "bad target"}, 400)
    rev = _reviews[rid]
    cached = (_review_translations.get(rid) or {}).get(target)
    if cached and not force:
        return _json({"ok": True, "text": cached, "cached": True})
    src = rev.get("public_review") or ""
    if not src.strip():
        return _json({"ok": True, "text": "", "cached": False})
    try:
        out = await asyncio.to_thread(claude_translate_review_text, src, target)
    except Exception as e:
        return _json({"error": str(e)}, 500)
    if rid not in _review_translations:
        _review_translations[rid] = {}
    _review_translations[rid][target] = (out or "").strip()
    await asyncio.to_thread(persist_state)
    return _json({"ok": True, "text": _review_translations[rid][target], "cached": False})

async def _api_reviews_bulk_analyze(request):
    """POST {lid?, sentiment?, days?, limit?} — analyze up to `limit` unprocessed
    reviews matching the filters. Caps cost: default limit 25.
    Background-safe — returns immediately with the count queued, the work runs
    in a thread so the dashboard doesn't lock up."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    try:
        lid_f = int(b.get("lid")) if b.get("lid") else None
    except Exception:
        lid_f = None
    sentiment = (b.get("sentiment") or "").strip()
    try:
        days = int(b.get("days") or 0)
    except Exception:
        days = 0
    try:
        limit = int(b.get("limit") or 25)
    except Exception:
        limit = 25
    limit = max(1, min(limit, 200))

    # Build the work list (collect all candidates, then prioritise negatives —
    # those are the ones that need the removability + reply analysis).
    candidates = []
    for rid, rev in _reviews.items():
        if rid in _review_ai_cache:
            continue
        if not (rev.get("public_review") or "").strip():
            continue
        if lid_f is not None and rev.get("listing_id") != lid_f: continue
        if not _review_in_window(rev, days): continue
        rating = rev.get("rating") or 0
        is_pos = rating >= 4
        if sentiment == "positive" and not is_pos: continue
        if sentiment == "negative" and is_pos: continue
        candidates.append((rid, rev, rating, is_pos))
    # negatives first, then lowest rating first, then newest first
    candidates.sort(key=lambda c: (c[3], c[2], ), )
    targets = [(rid, rev) for rid, rev, _r, _p in candidates[:limit]]

    if not targets:
        return _json({"ok": True, "queued": 0, "message": "ما فيه مراجعات تحتاج تحليل"})

    # Run in a worker so the request doesn't hang for minutes
    def _worker():
        done = 0
        for rid, rev in targets:
            try:
                out = claude_analyze_review(rev)
                if out:
                    _review_ai_cache[rid] = out
                    done += 1
            except Exception as e:
                print(f"bulk_analyze {rid} error:", e)
        try:
            persist_state()
        except Exception:
            pass
        log_event("ops", f"المراجعات · تحليل جماعي · {done}/{len(targets)} ✓")

    asyncio.get_event_loop().run_in_executor(None, _worker)
    return _json({"ok": True, "queued": len(targets),
                  "message": f"بدأ تحليل {len(targets)} مراجعة في الخلفية"})

def _review_analyze_targets(lid_f=None, sentiment="", days=0):
    """Build the full unanalyzed-review work list, negatives first (lowest
    rating first). Shared by the bulk 'analyze everything' job and the
    background auto-analyze loop."""
    cands = []
    for rid, rev in _reviews.items():
        if rid in _review_ai_cache:
            continue
        if not (rev.get("public_review") or "").strip():
            continue
        if lid_f is not None and rev.get("listing_id") != lid_f:
            continue
        if not _review_in_window(rev, days):
            continue
        rating = rev.get("rating") or 0
        is_pos = rating >= 4
        if sentiment == "positive" and not is_pos:
            continue
        if sentiment == "negative" and is_pos:
            continue
        cands.append((rid, rev, rating, is_pos))
    cands.sort(key=lambda c: (c[3], c[2]))  # negatives first, lowest rating first
    return [(rid, rev) for rid, rev, _r, _p in cands]

def _run_review_bulk_job(targets):
    """Analyze every review in `targets` concurrently with a worker pool, while
    updating _review_bulk_job for live dashboard progress. Runs in a daemon
    thread (started by the analyze-all endpoint)."""
    global _review_bulk_job
    _review_bulk_job = {"running": True, "total": len(targets), "done": 0,
                        "errors": 0, "started": int(time.time()), "finished": 0}

    def _one(item):
        rid, rev = item
        try:
            out = claude_analyze_review(rev)
            if out:
                _review_ai_cache[rid] = out
                return (rid, True)
        except Exception as e:
            print(f"analyze-all {rid} error:", e)
        return (rid, False)

    try:
        with ThreadPoolExecutor(max_workers=max(1, REVIEW_ANALYZE_WORKERS)) as ex:
            futs = [ex.submit(_one, it) for it in targets]
            for fut in as_completed(futs):
                try:
                    _rid, ok = fut.result()
                except Exception:
                    ok = False
                if ok:
                    _review_bulk_job["done"] += 1
                else:
                    _review_bulk_job["errors"] += 1
                processed = _review_bulk_job["done"] + _review_bulk_job["errors"]
                if processed % 25 == 0:
                    try:
                        persist_state()
                    except Exception:
                        pass
    finally:
        _review_bulk_job["running"] = False
        _review_bulk_job["finished"] = int(time.time())
        try:
            persist_state()
        except Exception:
            pass
        log_event("ops", f"المراجعات · تحليل الكل · {_review_bulk_job['done']}/{_review_bulk_job['total']} ✓")

async def _api_reviews_analyze_all(request):
    """POST {lid?, sentiment?, days?} — analyze EVERY unanalyzed review now,
    in parallel, with live progress. Guards against double-runs."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    if not ANTHROPIC_API_KEY:
        return _json({"error": "no_api_key", "message": "مفتاح Claude غير مهيأ"}, 400)
    if _review_bulk_job.get("running"):
        return _json({"ok": True, "already_running": True,
                      "total": _review_bulk_job.get("total", 0),
                      "done": _review_bulk_job.get("done", 0),
                      "message": "التحليل شغّال حالياً"})
    b = await _read_body(request)
    try:
        lid_f = int(b.get("lid")) if b.get("lid") else None
    except Exception:
        lid_f = None
    sentiment = (b.get("sentiment") or "").strip()
    try:
        days = int(b.get("days") or 0)
    except Exception:
        days = 0
    targets = _review_analyze_targets(lid_f, sentiment, days)
    if not targets:
        return _json({"ok": True, "total": 0, "message": "كل المراجعات محلّلة ✓"})
    t = threading.Thread(target=_run_review_bulk_job, args=(targets,), daemon=True)
    t.start()
    return _json({"ok": True, "total": len(targets),
                  "message": f"بدأ تحليل {len(targets)} مراجعة"})

async def _api_reviews_analyze_status(request):
    """GET — live progress of the analyze-everything job + total analyzed."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    job = dict(_review_bulk_job)
    job["analyzed_total"] = len(_review_ai_cache)
    job["reviews_total"] = len(_reviews)
    return _json(job)

async def _api_reviews_open_ticket(request):
    """POST {id} → open a maintenance ticket from a review (idempotent)."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    rid = str(b.get("id") or "").strip()
    if not rid or rid not in _reviews:
        return _json({"error": "review not found"}, 404)
    rev = _reviews[rid]
    state = _review_states.setdefault(rid, {})
    # Idempotent: if a ticket already exists for this review, return it
    if state.get("ticket_id"):
        existing = next((t for t in _tickets if t.get("id") == state["ticket_id"]), None)
        if existing:
            return _json({"ok": True, "ticket": _ticket_view(existing), "existing": True})
    listings = get_listings_map() or {}
    unit_name = listings.get(rev.get("listing_id"), "") or "—"
    ai = _review_ai_cache.get(rid) or {}
    title = f"مراجعة سلبية · {unit_name} · {rev.get('guest_name','—')} ({rev.get('rating',0)}/5)"[:120]
    body_lines = []
    if rev.get("public_review"):
        body_lines.append("نص المراجعة:")
        body_lines.append(rev["public_review"][:500])
    if rev.get("private_review"):
        body_lines.append("\nرسالة خاصة:")
        body_lines.append(rev["private_review"][:300])
    if ai.get("removability_reason_ar"):
        body_lines.append("\nتحليل AI لقابلية الحذف:")
        body_lines.append(ai["removability_reason_ar"][:400])
    description = "\n".join(body_lines)
    t = _ticket_create(
        title=title,
        description=description,
        lid=rev.get("listing_id"),
        priority="high" if (rev.get("rating") or 0) <= 2 else "med",
        category="صيانة",
        source="review",
        source_ref=rid,
        guest=rev.get("guest_name"),
        created_by=(b.get("by") or "owner"),
    )
    state["ticket_id"] = t["id"]
    state["last_edit_by"] = (b.get("by") or "owner").strip() or "owner"
    state["last_edit_at"] = datetime.now(TZ).isoformat(timespec="seconds")
    await asyncio.to_thread(persist_state)
    return _json({"ok": True, "ticket": _ticket_view(t), "existing": False})

# ===================== USERS + AUTH API =====================
# Basic in-memory brute-force throttle: per client IP, max attempts per window.
_login_attempts = {}            # ip -> [timestamps of recent failed attempts]
_LOGIN_MAX_FAILS = 5
_LOGIN_WINDOW_S  = 60

def _login_blocked(ip):
    """True if this IP has too many recent failed logins. Prunes old entries."""
    now = time.time()
    fails = [t for t in _login_attempts.get(ip, []) if now - t < _LOGIN_WINDOW_S]
    _login_attempts[ip] = fails
    return len(fails) >= _LOGIN_MAX_FAILS

def _login_record_fail(ip):
    _login_attempts.setdefault(ip, []).append(time.time())

async def _api_auth_login(request):
    """POST {username, password} → {ok:true, token, user}.
    Token is a session token good for 30 days."""
    ip = request.remote or "?"
    if _login_blocked(ip):
        return _json({"error": "too many attempts, try again later"}, 429)
    b = await _read_body(request)
    name = (b.get("username") or "").strip()
    pw   = b.get("password") or ""
    if not name or not pw:
        return _json({"error": "username and password required"}, 400)
    u = _find_user_by_name(name)
    if not u or not u.get("active"):
        _login_record_fail(ip)
        return _json({"error": "invalid credentials"}, 401)
    if not _verify_password(pw, u.get("password_hash", "")):
        _login_record_fail(ip)
        return _json({"error": "invalid credentials"}, 401)
    _login_attempts.pop(ip, None)   # success clears the counter
    tok = _new_session_token()
    _sessions[tok] = {
        "user_id": u["id"],
        "expires_at": time.time() + 30 * 86400,
    }
    return _json({"ok": True, "token": tok, "user": _user_view(u)})

async def _api_auth_logout(request):
    token = request.query.get("token") or request.headers.get("X-Token", "")
    if token:
        _sessions.pop(token, None)
    return _json({"ok": True})

async def _api_users_me(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    token = request.query.get("token") or request.headers.get("X-Token", "")
    if DASHBOARD_TOKEN and hmac.compare_digest(token, DASHBOARD_TOKEN):
        # legacy super-admin — synthesise a fake admin user
        return _json({"ok": True, "user": {"id": "owner", "name": "Owner",
                                            "role": "admin",
                                            "perms": _default_perms("admin")}})
    u = _auth_session(request)
    return _json({"ok": True, "user": _user_view(u)})

async def _api_users_list(request):
    if not _user_can(request, "users", "read"):
        return _json({"error": "forbidden"}, 403)
    items = [_user_view(u) for u in _users.values()]
    items.sort(key=lambda x: x.get("created_at") or "", reverse=True)
    return _json({"users": items,
                  "tabs": _USER_TABS,
                  "roles": ["admin", "ops", "viewer"]})

async def _api_users_create(request):
    if not _user_can(request, "users", "create"):
        return _json({"error": "forbidden"}, 403)
    b = await _read_body(request)
    name = (b.get("name") or "").strip()
    pw   = b.get("password") or ""
    role = (b.get("role") or "viewer").strip()
    perms = b.get("perms")  # optional override
    if not name:
        return _json({"error": "name required"}, 400)
    if len(pw) < 6:
        return _json({"error": "password must be at least 6 characters"}, 400)
    if _find_user_by_name(name):
        return _json({"error": "user with that name already exists"}, 409)
    u = _user_create(name, pw, role=role, perms=perms,
                     created_by=(b.get("by") or "admin"))
    await asyncio.to_thread(persist_state)
    log_event("ops", f"مستخدم جديد · {u['name']} ({u['role']})")
    return _json({"ok": True, "user": _user_view(u)})

async def _api_users_update(request):
    """POST {id, name?, role?, perms?, active?, password?} (admin only)"""
    if not _user_can(request, "users", "write"):
        return _json({"error": "forbidden"}, 403)
    b = await _read_body(request)
    uid = (b.get("id") or "").strip()
    u = _users.get(uid)
    if not u:
        return _json({"error": "user not found"}, 404)
    changed = []
    for k in ("name", "role"):
        if k in b and b[k] is not None and b[k] != u.get(k):
            if k == "role" and b[k] not in ("admin", "ops", "viewer"):
                continue
            u[k] = b[k]
            changed.append(k)
    if "active" in b:
        u["active"] = bool(b["active"])
        changed.append("active")
    if isinstance(b.get("perms"), dict):
        # Sanitise: only allow known tabs and known actions
        new_perms = {}
        for tab in _USER_TABS:
            cur = (b["perms"].get(tab) or {})
            new_perms[tab] = {
                "read":   bool(cur.get("read")),
                "write":  bool(cur.get("write")),
                "create": bool(cur.get("create")),
            }
        u["perms"] = new_perms
        changed.append("perms")
    if b.get("password"):
        if len(b["password"]) < 6:
            return _json({"error": "password must be at least 6 characters"}, 400)
        u["password_hash"] = _hash_password(b["password"])
        changed.append("password")
    await asyncio.to_thread(persist_state)
    if changed:
        log_event("ops", f"مستخدم · تحديث {u.get('name','?')} · {', '.join(changed)}")
    return _json({"ok": True, "user": _user_view(u)})

async def _api_users_delete(request):
    if not _user_can(request, "users", "write"):
        return _json({"error": "forbidden"}, 403)
    b = await _read_body(request)
    uid = (b.get("id") or "").strip()
    u = _users.pop(uid, None)
    if not u:
        return _json({"error": "user not found"}, 404)
    # invalidate any active sessions for this user
    for tok, sess in list(_sessions.items()):
        if sess.get("user_id") == uid:
            _sessions.pop(tok, None)
    await asyncio.to_thread(persist_state)
    log_event("ops", f"مستخدم · حذف {u.get('name','?')}")
    return _json({"ok": True})

# ===================== QUOTATIONS API =====================
def _quote_totals(items, service_rate, vat_rate, vat_on):
    """Compute totals from a quote's items + rates. All amounts in SAR."""
    subtotal = 0.0
    for it in (items or []):
        try:
            qty = float(it.get("qty") or 0)
            price = float(it.get("price") or 0)
            subtotal += qty * price
        except Exception:
            pass
    service_amt = subtotal * (float(service_rate or 0) / 100.0)
    base_for_vat = subtotal + service_amt
    vat_amt = base_for_vat * (float(vat_rate or 0) / 100.0) if vat_on else 0.0
    return {
        "subtotal":    round(subtotal, 2),
        "service_amt": round(service_amt, 2),
        "vat_amt":     round(vat_amt, 2),
        "grand_total": round(subtotal + service_amt + vat_amt, 2),
    }

async def _api_quotes_list(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    items = list(_quotes.values())
    items.sort(key=lambda q: q.get("created_at") or "", reverse=True)
    # trim large fields from the list view
    out = []
    for q in items:
        out.append({
            "id": q.get("id"), "number": q.get("number"),
            "date": q.get("date"), "client_name": q.get("client_name"),
            "client_phone": q.get("client_phone"),
            "status": q.get("status", "draft"),
            "grand_total": q.get("totals", {}).get("grand_total", 0),
            "created_at": q.get("created_at"),
            "created_by": q.get("created_by"),
        })
    # Item 46: overall win-rate = accepted / (accepted + lost).
    won = sum(1 for q in items if q.get("status") == "accepted")
    lost = sum(1 for q in items if q.get("status") == "lost")
    sent = sum(1 for q in items if q.get("status") in ("sent", "accepted", "lost"))
    decided = won + lost
    win_rate = round(won * 100 / decided) if decided else None
    return _json({"quotes": out, "count": len(out),
                  "stats": {"won": won, "lost": lost, "sent": sent,
                            "decided": decided, "win_rate": win_rate}})

async def _api_quotes_get(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    qid = request.query.get("id", "")
    q = _quotes.get(qid)
    if not q:
        return _json({"error": "not found"}, 404)
    return _json({"quote": q})

async def _api_quotes_save(request):
    """POST {id?, number?, date?, client_*, items, service_rate, vat_rate,
       vat_on, notes, signature_name}"""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    qid = (b.get("id") or "").strip()
    is_new = not qid or qid not in _quotes
    if is_new:
        qid = qid or _new_quote_id()
        q = {
            "id": qid,
            "number": b.get("number") or _new_quote_number(),
            "created_at": datetime.now(TZ).isoformat(timespec="seconds"),
            "created_by": (b.get("by") or "owner"),
        }
        _quotes[qid] = q
    else:
        q = _quotes[qid]
    # Update fields
    for k in ("number", "date", "client_name", "client_phone", "client_company",
              "client_email", "notes", "signature_name", "status"):
        if k in b:
            q[k] = (b[k] or "").strip() if isinstance(b[k], str) else b[k]
    if isinstance(b.get("items"), list):
        cleaned = []
        for it in b["items"]:
            if not isinstance(it, dict): continue
            cleaned.append({
                "description": (it.get("description") or "").strip()[:300],
                "note": (it.get("note") or "").strip()[:200],
                "qty": float(it.get("qty") or 0),
                "price": float(it.get("price") or 0),
            })
        q["items"] = cleaned
    if "service_rate" in b:
        try: q["service_rate"] = float(b["service_rate"])
        except Exception: pass
    if "vat_rate" in b:
        try: q["vat_rate"] = float(b["vat_rate"])
        except Exception: pass
    if "vat_on" in b:
        q["vat_on"] = bool(b["vat_on"])
    # Recompute totals
    q["totals"] = _quote_totals(q.get("items"), q.get("service_rate", 5),
                                 q.get("vat_rate", 15), q.get("vat_on", True))
    q["updated_at"] = datetime.now(TZ).isoformat(timespec="seconds")
    await asyncio.to_thread(persist_state)
    if is_new:
        log_event("ops", f"عرض سعر جديد · {q['number']} · {q.get('client_name','—')}"
                         + f" · {q['totals']['grand_total']} ر.س")
    return _json({"ok": True, "quote": q, "is_new": is_new})

async def _api_quotes_delete(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    qid = (b.get("id") or "").strip()
    q = _quotes.pop(qid, None)
    if not q:
        return _json({"error": "not found"}, 404)
    await asyncio.to_thread(persist_state)
    log_event("ops", f"عرض سعر · حذف {q.get('number','?')}")
    return _json({"ok": True})

# ===================== WEEKLY REPORTS API =====================
async def _api_weekly_list(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    items = list(_weekly_reports.values())
    items.sort(key=lambda r: r.get("created_at") or "", reverse=True)
    out = []
    for r in items[:200]:
        out.append({
            "id": r.get("id"), "employee": r.get("employee"),
            "date": r.get("date"),
            "apt_count": len(r.get("apartments") or []),
            "summary": r.get("summary") or _wr_summary(r.get("apartments") or []),
            "created_at": r.get("created_at"),
        })
    return _json({"reports": out, "count": len(items)})

async def _api_weekly_get(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    rid = request.query.get("id", "")
    r = _weekly_reports.get(rid)
    if not r:
        return _json({"error": "not found"}, 404)
    return _json({"report": r})

def _wr_is_resolved(apt):
    """True if this apartment row is fully resolved (so it should NOT carry over)."""
    res = (apt.get("resolved") or "").strip().lower()
    return res in ("نعم", "yes", "تم الحل", "resolved")

def _wr_open_issues(apt):
    """Structured issues on an apartment row that are still open (resolved != True)."""
    return [it for it in (apt.get("issues") or [])
            if isinstance(it, dict) and not it.get("resolved")]

def _wr_latest_prior(before_date):
    """The most recent saved report strictly before `before_date` (ISO yyyy-mm-dd)."""
    cands = [r for r in _weekly_reports.values()
             if (r.get("date") or "") and (r.get("date") or "") < (before_date or "9999")]
    cands.sort(key=lambda r: (r.get("date") or "", r.get("created_at") or ""), reverse=True)
    return cands[0] if cands else None

def _wr_summary(apts):
    """Auto-computed report header counts (§Part 2 'auto summary')."""
    apts = apts or []
    total = len(apts)
    with_issue = sum(1 for a in apts if _wr_open_issues(a)
                     or any(v == "issue" for v in (a.get("checks") or {}).values())
                     or any(r not in ("لا يوجد خطر", "No risk") for r in (a.get("risks") or [])))
    resolved = sum(1 for a in apts if _wr_is_resolved(a))
    carried = sum(1 for a in apts for it in _wr_open_issues(a) if (it.get("weeks") or 1) > 1)
    high = sum(1 for a in apts for it in _wr_open_issues(a) if (it.get("severity") == "high"))
    occupied = sum(1 for a in apts if a.get("occupied"))
    return {"total": total, "with_issue": with_issue, "resolved": resolved,
            "unresolved": max(0, with_issue - resolved), "carried": carried,
            "high": high, "occupied": occupied}

async def _api_weekly_template(request):
    """GET → all apartments pre-listed, each auto-enriched with: most-common review
    issues, NEW reviews in the last 7 days, currently-open maintenance tickets,
    current occupancy, and any unresolved issues carried over from the previous
    week's report (with a week counter). Lets the employee just tick the checklist
    and review what the system already knows instead of starting from a blank page."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    seed = _reviews_insights or {}
    seed_apts = seed.get("apartments", {}) or {}
    try:
        listings = await asyncio.to_thread(get_listings_map)
    except Exception:
        listings = {}
    # --- current occupancy (one targeted in-house query) ---
    today = datetime.now(TZ).date()
    occ_lids = set()
    try:
        rows = await asyncio.to_thread(fetch_inhouse, today)
        for r in rows:
            a, d = _parse_date(r.get("arrivalDate")), _parse_date(r.get("departureDate"))
            if a and d and a <= today < d:
                occ_lids.add(str(r.get("listingMapId")))
    except Exception:
        pass
    # --- new reviews in the last 7 days, per listing ---
    wk_ago = (today - timedelta(days=7)).isoformat()
    new_rev = {}
    for rv in _reviews.values():
        lid = rv.get("listing_id")
        if lid is None:
            continue
        if (rv.get("date") or "") >= wk_ago:
            new_rev[str(lid)] = new_rev.get(str(lid), 0) + 1
    # --- open tickets per listing ---
    open_tk = {}
    for t in _tickets:
        if t.get("status") in ("open", "in_progress") and t.get("lid") is not None:
            open_tk.setdefault(str(t["lid"]), []).append(
                {"title": t.get("title") or "", "priority": t.get("priority") or "med",
                 "status": t.get("status")})
    # --- carry-over from the previous report ---
    prior = _wr_latest_prior(today.isoformat())
    carry_by_lid, carry_by_name = {}, {}
    if prior:
        for a in (prior.get("apartments") or []):
            opens = _wr_open_issues(a)
            if not opens:
                continue
            carried = []
            for it in opens:
                c = dict(it)
                c["weeks"] = int(c.get("weeks") or 1) + 1
                c["carried"] = True
                carried.append(c)
            if a.get("listing_id") is not None:
                carry_by_lid[str(a["listing_id"])] = carried
            if a.get("name"):
                carry_by_name[a["name"]] = carried

    def enrich(name, lid):
        k = str(lid) if lid is not None else None
        carried = (carry_by_lid.get(k) if k else None) or carry_by_name.get(name) or []
        return {
            "new_reviews": (new_rev.get(k, 0) if k else 0),
            "open_tickets": (open_tk.get(k, []) if k else []),
            "occupied": (k in occ_lids) if k else False,
            "issues": [dict(c) for c in carried],
        }

    apts, seen = [], set()
    for nm, s in sorted(seed_apts.items(), key=lambda kv: kv[0]):
        lid = s.get("listing_id")
        cur = listings.get(int(lid)) if (lid and str(lid).isdigit()) else None
        name = cur or nm
        e = enrich(name, lid)
        apts.append({
            "name": name, "listing_id": lid,
            "common_issues": [it.get("tag") for it in (s.get("issues") or []) if it.get("tag")][:6],
            **e,
        })
        if lid is not None:
            seen.add(str(lid))
    for lid, name in sorted(listings.items(), key=lambda kv: str(kv[1])):
        if str(lid) in seen:
            continue
        apts.append({"name": name, "listing_id": lid, "common_issues": [], **enrich(name, lid)})
    return _json({"apartments": apts, "count": len(apts),
                  "carried_from": (prior or {}).get("date")})

async def _api_weekly_save(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    rid = (b.get("id") or "").strip()
    is_new = not rid or rid not in _weekly_reports
    if is_new:
        rid = rid or _new_report_id()
        r = {"id": rid, "created_at": datetime.now(TZ).isoformat(timespec="seconds")}
        _weekly_reports[rid] = r
    else:
        r = _weekly_reports[rid]
    for k in ("employee", "date"):
        if k in b: r[k] = (b[k] or "").strip()
    # Report-level free-text fields (§Part 2)
    if "highlights" in b: r["highlights"] = (b.get("highlights") or "").strip()[:2000]
    if "unusual" in b:    r["unusual"]    = (b.get("unusual") or "").strip()[:2000]
    if isinstance(b.get("apartments"), list):
        cleaned = []
        for apt in b["apartments"]:
            if not isinstance(apt, dict): continue
            checks = {}
            if isinstance(apt.get("checks"), dict):
                for k, v in list(apt["checks"].items())[:40]:
                    checks[str(k)[:60]] = str(v)[:10]
            # Structured, trackable issues (severity / assignee / follow-up / week count)
            issues = []
            for it in (apt.get("issues") or [])[:30]:
                if not isinstance(it, dict): continue
                txt = (it.get("text") or "").strip()[:200]
                if not txt: continue
                sev = (it.get("severity") or "med")
                issues.append({
                    "text":     txt,
                    "severity": sev if sev in ("low", "med", "high") else "med",
                    "assignee": (it.get("assignee") or "").strip()[:60],
                    "followup": (it.get("followup") or "").strip()[:10],
                    "weeks":    int(it.get("weeks") or 1),
                    "carried":  bool(it.get("carried")),
                    "resolved": bool(it.get("resolved")),
                })
            cleaned.append({
                "name":      (apt.get("name") or "").strip()[:80],
                "listing_id": apt.get("listing_id"),
                "status":    (apt.get("status") or "").strip()[:40],
                "risks":     [str(x)[:120] for x in (apt.get("risks") or [])][:20],
                "updates":   [str(x)[:160] for x in (apt.get("updates") or [])][:20],
                "challenges":[str(x)[:120] for x in (apt.get("challenges") or [])][:20],
                "plan":      [str(x)[:200] for x in (apt.get("plan") or [])][:20],
                "supervisor":[str(x)[:160] for x in (apt.get("supervisor") or [])][:20],
                "resolved":  (apt.get("resolved") or "").strip()[:40],
                "risks_other":      (apt.get("risks_other") or "").strip()[:200],
                "updates_other":    (apt.get("updates_other") or "").strip()[:200],
                "plan_other":       (apt.get("plan_other") or "").strip()[:200],
                "supervisor_other": (apt.get("supervisor_other") or "").strip()[:200],
                "comments":  [str(x)[:200] for x in (apt.get("comments") or [])][:20],
                "common_issues": [str(x)[:60] for x in (apt.get("common_issues") or [])][:10],
                "issues":    issues,
                "new_reviews": int(apt.get("new_reviews") or 0),
                "open_tickets": [
                    {"title": str(t.get("title", ""))[:120],
                     "priority": str(t.get("priority", "med"))[:10],
                     "status": str(t.get("status", ""))[:20]}
                    for t in (apt.get("open_tickets") or []) if isinstance(t, dict)][:20],
                "occupied":  bool(apt.get("occupied")),
                "checks":    checks,
            })
        r["apartments"] = cleaned
        r["summary"] = _wr_summary(cleaned)
    r["updated_at"] = datetime.now(TZ).isoformat(timespec="seconds")
    await asyncio.to_thread(persist_state)
    if is_new:
        log_event("ops", f"تقرير أسبوعي · {r.get('employee','?')} · "
                         f"{len(r.get('apartments') or [])} شقة")
    return _json({"ok": True, "report": r, "is_new": is_new})

async def _api_weekly_delete(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
